window.KJV1769_STRONG_BOOKS["Esth"] = {"osis":"Esth","book":"에스더","verses":{"1:1":{"text":"Now it came to pass in the days of Ahasuerus, (this is Ahasuerus which reigned, from India even unto Ethiopia, over an hundred and seven and twenty provinces:)","words":[["H3117","Now it came to pass in the days",0,31],["H0325","of Ahasuerus",32,44],["H0325","(this is Ahasuerus",46,64],["H4427","which reigned",65,78],["H1912","from India",80,90],["H3568","even unto Ethiopia",91,109],["H3967","over an hundred",111,126],["H7651","and seven",127,136],["H6242","and twenty",137,147],["H4082","provinces",148,157]]},"1:2":{"text":"That in those days, when the king Ahasuerus sat on the throne of his kingdom, which was in Shushan the palace,","words":[["H3117","That in those days",0,18],["H4428","when the king",20,33],["H0325","Ahasuerus",34,43],["H3427","sat",44,47],["H3678","on the throne",48,61],["H4438","of his kingdom",62,76],["H7800","which was in Shushan",78,98],["H1002","the palace",99,109]]},"1:3":{"text":"In the third year of his reign, he made a feast unto all his princes and his servants; the power of Persia and Media, the nobles and princes of the provinces, being before him:","words":[["H7969","In the third",0,12],["H8141","year",13,17],["H4427","of his reign",18,30],["H6213","he made",32,39],["H4960","a feast",40,47],["H8269","unto all his princes",48,68],["H5650","and his servants",69,85],["H2428","the power",87,96],["H6539","of Persia",97,106],["H4074","and Media",107,116],["H6579","the nobles",118,128],["H8269","and princes",129,140],["H4082","of the provinces",141,157],["H6440","being before",159,171]]},"1:4":{"text":"When he shewed the riches of his glorious kingdom and the honour of his excellent majesty many days, even an hundred and fourscore days.","words":[["H7200","When he shewed",0,14],["H6239","the riches",15,25],["H3519","of his glorious",26,41],["H4438","kingdom",42,49],["H3366","and the honour",50,64],["H8597","of his excellent",65,81],["H1420","majesty",82,89],["H7227","many",90,94],["H3117","days",95,99],["H3967","even an hundred",101,116],["H8084","and fourscore",117,130],["H3117","days",131,135]]},"1:5":{"text":"And when these days were expired, the king made a feast unto all the people that were present in Shushan the palace, both unto great and small, seven days, in the court of the garden of the king's palace;","words":[["H3117","And when these days",0,19],["H4390","were expired",20,32],["H4428","the king",34,42],["H6213","made",43,47],["H4960","a feast",48,55],["H5971","unto all the people",56,75],["H4672","that were present",76,93],["H7800","in Shushan",94,104],["H1002","the palace",105,115],["H1419","both unto great",117,132],["H6996","and small",133,142],["H7651","seven",144,149],["H3117","days",150,154],["H2691","in the court",156,168],["H1594","of the garden",169,182],["H4428","of the king's",183,196],["H1055","palace",197,203]]},"1:6":{"text":"Where were white, green, and blue, hangings, fastened with cords of fine linen and purple to silver rings and pillars of marble: the beds were of gold and silver, upon a pavement of red, and blue, and white, and black, marble.","words":[["H2353","Where were white",0,16],["H3768","green",18,23],["H8504","and blue",25,33],["H0270","hangings, fastened",35,53],["H2256","with cords",54,64],["H0948","of fine linen",65,78],["H0713","and purple",79,89],["H3701","to silver",90,99],["H1550","rings",100,105],["H5982","and pillars",106,117],["H8336","of marble",118,127],["H4296","the beds",129,137],["H2091","were of gold",138,150],["H3701","and silver",151,161],["H7531","upon a pavement",163,178],["H0923","of red",179,185],["H8504","and blue",187,195],["H1858","and white",197,206],["H5508","and black",208,217],["H8336","marble",219,225]]},"1:7":{"text":"And they gave them drink in vessels of gold, (the vessels being diverse one from another,) and royal wine in abundance, according to the state of the king.","words":[["H8248","And they gave them drink",0,24],["H3627","in vessels",25,35],["H2091","of gold",36,43],["H3627","(the vessels",45,57],["H8138","being diverse",58,71],["H3627","one from another",72,88],["H4438",") and royal",89,100],["H3196","wine",101,105],["H7227","in abundance",106,118],["H3027","according to the state",120,142],["H4428","of the king",143,154]]},"1:8":{"text":"And the drinking was according to the law; none did compel: for so the king had appointed to all the officers of his house, that they should do according to every man's pleasure.","words":[["H8360","And the drinking",0,16],["H1881","was according to the law",17,41],["H0597","none did compel",43,58],["H4428","for so the king",60,75],["H3245","had appointed",76,89],["H7227","to all the officers",90,109],["H1004","of his house",110,122],["H6213","that they should do",124,143],["H0376","according to every man's",144,168],["H7522","pleasure",169,177]]},"1:9":{"text":"Also Vashti the queen made a feast for the women in the royal house which belonged to king Ahasuerus.","words":[["H2060","Also Vashti",0,11],["H4436","the queen",12,21],["H6213","made",22,26],["H4960","a feast",27,34],["H0802","for the women",35,48],["H4438","in the royal",49,61],["H1004","house",62,67],["H4428","which belonged to king",68,90],["H0325","Ahasuerus",91,100]]},"1:10":{"text":"On the seventh day, when the heart of the king was merry with wine, he commanded Mehuman, Biztha, Harbona, Bigtha, and Abagtha, Zethar, and Carcas, the seven chamberlains that served in the presence of Ahasuerus the king,","words":[["H7637","On the seventh",0,14],["H3117","day",15,18],["H3820","when the heart",20,34],["H4428","of the king",35,46],["H2896","was merry",47,56],["H3196","with wine",57,66],["H0559","he commanded",68,80],["H4104","Mehuman",81,88],["H0968","Biztha",90,96],["H2726","Harbona",98,105],["H0903","Bigtha",107,113],["H0005","and Abagtha",115,126],["H2242","Zethar",128,134],["H3752","and Carcas",136,146],["H7651","the seven",148,157],["H5631","chamberlains",158,170],["H8334","that served",171,182],["H6440","in the presence",183,198],["H0325","of Ahasuerus",199,211],["H4428","the king",212,220]]},"1:11":{"text":"To bring Vashti the queen before the king with the crown royal, to shew the people and the princes her beauty: for she was fair to look on.","words":[["H0935","To bring",0,8],["H2060","Vashti",9,15],["H4436","the queen",16,25],["H6440","before",26,32],["H4428","the king",33,41],["H3804","with the crown",42,56],["H4438","royal",57,62],["H7200","to shew",64,71],["H5971","the people",72,82],["H8269","and the princes",83,98],["H3308","her beauty",99,109],["H2896","for she was fair",111,127],["H4758","to look on",128,138]]},"1:12":{"text":"But the queen Vashti refused to come at the king's commandment by his chamberlains: therefore was the king very wroth, and his anger burned in him.","words":[["H4436","But the queen",0,13],["H2060","Vashti",14,20],["H3985","refused",21,28],["H0935","to come",29,36],["H4428","at the king's",37,50],["H1697","commandment",51,62],["H3027","by",63,65],["H5631","his chamberlains",66,82],["H4428","therefore was the king",84,106],["H3966","very",107,111],["H7107","wroth",112,117],["H2534","and his anger",119,132],["H1197","burned",133,139]]},"1:13":{"text":"Then the king said to the wise men, which knew the times, (for so was the king's manner toward all that knew law and judgment:","words":[["H4428","Then the king",0,13],["H0559","said",14,18],["H2450","to the wise men",19,34],["H3045","which knew",36,46],["H6256","the times",47,56],["H4428","(for so was the king's",58,80],["H1697","manner",81,87],["H6440","toward",88,94],["H3045","all that knew",95,108],["H1881","law",109,112],["H1779","and judgment",113,125]]},"1:14":{"text":"And the next unto him was Carshena, Shethar, Admatha, Tarshish, Meres, Marsena, and Memucan, the seven princes of Persia and Media, which saw the king's face, and which sat the first in the kingdom;)","words":[["H7138","And the next",0,12],["H3771","unto him was Carshena",13,34],["H8369","Shethar",36,43],["H0133","Admatha",45,52],["H8659","Tarshish",54,62],["H4825","Meres",64,69],["H4826","Marsena",71,78],["H4462","and Memucan",80,91],["H7651","the seven",93,102],["H8269","princes",103,110],["H6539","of Persia",111,120],["H4074","and Media",121,130],["H7200","which saw",132,141],["H4428","the king's",142,152],["H6440","face",153,157],["H3427","and which sat",159,172],["H7223","the first",173,182],["H4438","in the kingdom",183,197]]},"1:15":{"text":"What shall we do unto the queen Vashti according to law, because she hath not performed the commandment of the king Ahasuerus by the chamberlains?","words":[["H6213","What shall we do",0,16],["H4436","unto the queen",17,31],["H2060","Vashti",32,38],["H1881","according to law",39,55],["H6213","because she hath not performed",57,87],["H3982","the commandment",88,103],["H4428","of the king",104,115],["H0325","Ahasuerus",116,125],["H3027","by",126,128],["H5631","the chamberlains",129,145]]},"1:16":{"text":"And Memucan answered before the king and the princes, Vashti the queen hath not done wrong to the king only, but also to all the princes, and to all the people that are in all the provinces of the king Ahasuerus.","words":[["H4462","And Memucan",0,11],["H0559","answered",12,20],["H6440","before",21,27],["H4428","the king",28,36],["H8269","and the princes",37,52],["H2060","Vashti",54,60],["H4436","the queen",61,70],["H5753","hath not done wrong",71,90],["H4428","to the king",91,102],["H8269","only, but also to all the princes",103,136],["H5971","and to all the people",138,159],["H4082","that are in all the provinces",160,189],["H4428","of the king",190,201],["H0325","Ahasuerus",202,211]]},"1:17":{"text":"For this deed of the queen shall come abroad unto all women, so that they shall despise their husbands in their eyes, when it shall be reported, The king Ahasuerus commanded Vashti the queen to be brought in before him, but she came not.","words":[["H1697","For this deed",0,13],["H4436","of the queen",14,26],["H3318","shall come abroad",27,44],["H0802","unto all women",45,59],["H0959","so that they shall despise",61,87],["H1167","their husbands",88,102],["H5869","in their eyes",103,116],["H0559","when it shall be reported",118,143],["H4428","The king",145,153],["H0325","Ahasuerus",154,163],["H0559","commanded",164,173],["H2060","Vashti",174,180],["H4436","the queen",181,190],["H0935","to be brought in",191,207],["H6440","before",208,214],["H0935","him, but she came",215,232]]},"1:18":{"text":"Likewise shall the ladies of Persia and Media say this day unto all the king's princes, which have heard of the deed of the queen. Thus shall there arise too much contempt and wrath.","words":[["H8282","Likewise shall the ladies",0,25],["H6539","of Persia",26,35],["H4074","and Media",36,45],["H0559","say",46,49],["H3117","this day",50,58],["H4428","unto all the king's",59,78],["H8269","princes",79,86],["H8085","which have heard",88,104],["H1697","of the deed",105,116],["H4436","of the queen",117,129],["H1767","Thus shall there arise too much",131,162],["H0963","contempt",163,171],["H7110","and wrath",172,181]]},"1:19":{"text":"If it please the king, let there go a royal commandment from him, and let it be written among the laws of the Persians and the Medes, that it be not altered, That Vashti come no more before king Ahasuerus; and let the king give her royal estate unto another that is better than she.","words":[["H2895","If it please",0,12],["H4428","the king",13,21],["H3318","let there go",23,35],["H4438","a royal",36,43],["H1697","commandment",44,55],["H6440","from him",56,64],["H3789","and let it be written",66,87],["H1881","among the laws",88,102],["H6539","of the Persians",103,118],["H4074","and the Medes",119,132],["H5674","that it be not altered",134,156],["H2060","That Vashti",158,169],["H0935","come",170,174],["H6440","no more before",175,189],["H4428","king",190,194],["H0325","Ahasuerus",195,204],["H4428","and let the king",206,222],["H5414","give",223,227],["H4438","her royal estate",228,244],["H7468","unto another",245,257],["H2896","that is better",258,272]]},"1:20":{"text":"And when the king's decree which he shall make shall be published throughout all his empire, (for it is great,) all the wives shall give to their husbands honour, both to great and small.","words":[["H4428","And when the king's",0,19],["H6599","decree",20,26],["H6213","which he shall make",27,46],["H8085","shall be published",47,65],["H4438","throughout all his empire",66,91],["H7227","(for it is great",93,109],["H0802",") all the wives",110,125],["H5414","shall give",126,136],["H1167","to their husbands",137,154],["H3366","honour",155,161],["H1419","both to great",163,176],["H6996","and small",177,186]]},"1:21":{"text":"And the saying pleased the king and the princes; and the king did according to the word of Memucan:","words":[["H1697","And the saying",0,14],["H3190","pleased",15,22],["H5869","pleased",15,22],["H4428","the king",23,31],["H8269","and the princes",32,47],["H4428","and the king",49,61],["H6213","did",62,65],["H1697","according to the word",66,87],["H4462","of Memucan",88,98]]},"1:22":{"text":"For he sent letters into all the king's provinces, into every province according to the writing thereof, and to every people after their language, that every man should bear rule in his own house, and that it should be published according to the language of every people.","words":[["H7971","For he sent",0,11],["H5612","letters",12,19],["H4428","into all the king's",20,39],["H4082","provinces",40,49],["H4082","into every province",51,70],["H3791","according to the writing",71,95],["H5971","thereof, and to every people",96,124],["H3956","after their language",125,145],["H0376","that every man",147,161],["H8323","should bear rule",162,178],["H1004","in his own house",179,195],["H1696","and that it should be published",197,228],["H3956","according to the language",229,254],["H5971","of every people",255,270]]},"2:1":{"text":"After these things, when the wrath of king Ahasuerus was appeased, he remembered Vashti, and what she had done, and what was decreed against her.","words":[["H0310","After",0,5],["H1697","these things",6,18],["H2534","when the wrath",20,34],["H4428","of king",35,42],["H0325","Ahasuerus",43,52],["H7918","was appeased",53,65],["H2142","he remembered",67,80],["H2060","Vashti",81,87],["H6213","and what she had done",89,110],["H1504","and what was decreed",112,132]]},"2:2":{"text":"Then said the king's servants that ministered unto him, Let there be fair young virgins sought for the king:","words":[["H0559","Then said",0,9],["H4428","the king's",10,20],["H5288","servants",21,29],["H8334","that ministered",30,45],["H2896","unto him, Let there be fair",46,73],["H4758","unto him, Let there be fair",46,73],["H5291","young",74,79],["H1330","virgins",80,87],["H1245","sought",88,94],["H4428","for the king",95,107]]},"2:3":{"text":"And let the king appoint officers in all the provinces of his kingdom, that they may gather together all the fair young virgins unto Shushan the palace, to the house of the women, unto the custody of Hege the king's chamberlain, keeper of the women; and let their things for purification be given them:","words":[["H4428","And let the king",0,16],["H6485","appoint",17,24],["H6496","officers",25,33],["H4082","in all the provinces",34,54],["H4438","of his kingdom",55,69],["H6908","that they may gather together",71,100],["H2896","all the fair",101,113],["H4758","all the fair",101,113],["H5291","young",114,119],["H1330","virgins",120,127],["H7800","unto Shushan",128,140],["H1002","the palace",141,151],["H1004","to the house",153,165],["H0802","of the women",166,178],["H3027","unto the custody",180,196],["H1896","of Hege",197,204],["H4428","the king's",205,215],["H5631","chamberlain",216,227],["H8104","keeper",229,235],["H0802","of the women",236,248],["H8562","and let their things for purification",250,287],["H5414","be given",288,296]]},"2:4":{"text":"And let the maiden which pleaseth the king be queen instead of Vashti. And the thing pleased the king; and he did so.","words":[["H5291","And let the maiden",0,18],["H3190","which pleaseth",19,33],["H5869","which pleaseth",19,33],["H4428","the king",34,42],["H4427","be queen",43,51],["H2060","instead of Vashti",52,69],["H1697","And the thing",71,84],["H3190","pleased",85,92],["H5869","pleased",85,92],["H4428","the king",93,101],["H6213","and he did so",103,116]]},"2:5":{"text":"Now in Shushan the palace there was a certain Jew, whose name was Mordecai, the son of Jair, the son of Shimei, the son of Kish, a Benjamite;","words":[["H7800","Now in Shushan",0,14],["H1002","the palace",15,25],["H0376","there was a certain",26,45],["H3064","Jew",46,49],["H8034","whose name",51,61],["H4782","was Mordecai",62,74],["H1121","the son",76,83],["H2971","of Jair",84,91],["H1121","the son",93,100],["H8096","of Shimei",101,110],["H1121","the son",112,119],["H7027","of Kish",120,127],["H1145","a Benjamite",129,140]]},"2:6":{"text":"Who had been carried away from Jerusalem with the captivity which had been carried away with Jeconiah king of Judah, whom Nebuchadnezzar the king of Babylon had carried away.","words":[["H1540","Who had been carried away",0,25],["H3389","from Jerusalem",26,40],["H1473","with the captivity",41,59],["H1540","which had been carried away",60,87],["H3204","with Jeconiah",88,101],["H4428","king",102,106],["H3063","of Judah",107,115],["H5019","whom Nebuchadnezzar",117,136],["H4428","the king",137,145],["H0894","of Babylon",146,156],["H1540","had carried away",157,173]]},"2:7":{"text":"And he brought up Hadassah, that is, Esther, his uncle's daughter: for she had neither father nor mother, and the maid was fair and beautiful; whom Mordecai, when her father and mother were dead, took for his own daughter.","words":[["H0539","And he brought up",0,17],["H1919","Hadassah",18,26],["H0635","that is, Esther",28,43],["H1730","his uncle's",45,56],["H1323","daughter",57,65],["H0001","for she had neither father",67,93],["H0517","nor mother",94,104],["H5291","and the maid",106,118],["H3303","was fair",119,127],["H8389","was fair",119,127],["H2896","and beautiful",128,141],["H4758","and beautiful",128,141],["H4782","whom Mordecai",143,156],["H0001","when her father",158,173],["H0517","and mother",174,184],["H4194","were dead",185,194],["H3947","took",196,200],["H1323","for his own daughter",201,221]]},"2:8":{"text":"So it came to pass, when the king's commandment and his decree was heard, and when many maidens were gathered together unto Shushan the palace, to the custody of Hegai, that Esther was brought also unto the king's house, to the custody of Hegai, keeper of the women.","words":[["H4428","So it came to pass, when the king's",0,35],["H1697","commandment",36,47],["H1881","and his decree",48,62],["H8085","was heard",63,72],["H7227","and when many",74,87],["H5291","maidens",88,95],["H6908","were gathered together",96,118],["H7800","unto Shushan",119,131],["H1002","the palace",132,142],["H3027","to the custody",144,158],["H1896","of Hegai",159,167],["H0635","that Esther",169,180],["H3947","was brought",181,192],["H4428","also unto the king's",193,213],["H1004","house",214,219],["H3027","to the custody",221,235],["H1896","of Hegai",236,244],["H8104","keeper",246,252],["H0802","of the women",253,265]]},"2:9":{"text":"And the maiden pleased him, and she obtained kindness of him; and he speedily gave her her things for purification, with such things as belonged to her, and seven maidens, which were meet to be given her, out of the king's house: and he preferred her and her maids unto the best place of the house of the women.","words":[["H5291","And the maiden",0,14],["H3190","pleased",15,22],["H5869","pleased",15,22],["H5375","him, and she obtained",23,44],["H2617","kindness",45,53],["H6440","of him",54,60],["H0926","and he speedily",62,77],["H5414","gave",78,82],["H8562","her her things for purification",83,114],["H4490","with such things as belonged",116,144],["H7651","to her, and seven",145,162],["H5291","maidens",163,170],["H7200","which were meet",172,187],["H5414","to be given",188,199],["H4428","her, out of the king's",200,222],["H1004","house",223,228],["H8138","and he preferred",230,246],["H5291","her and her maids",247,264],["H2896","unto the best",265,278],["H1004","place of the house",279,297],["H0802","of the women",298,310]]},"2:10":{"text":"Esther had not shewed her people nor her kindred: for Mordecai had charged her that she should not shew it.","words":[["H0635","Esther",0,6],["H5046","had not shewed",7,21],["H5971","her people",22,32],["H4138","nor her kindred",33,48],["H4782","for Mordecai",50,62],["H6680","had charged",63,74],["H5046","her that she should not shew",75,103]]},"2:11":{"text":"And Mordecai walked every day before the court of the women's house, to know how Esther did, and what should become of her.","words":[["H4782","And Mordecai",0,12],["H1980","walked",13,19],["H3117","every day",20,29],["H6440","before",30,36],["H2691","the court",37,46],["H0802","of the women's",47,61],["H1004","house",62,67],["H3045","to know",69,76],["H0635","how Esther",77,87],["H7965","did",88,91],["H6213","and what should become",93,115]]},"2:12":{"text":"Now when every maid's turn was come to go in to king Ahasuerus, after that she had been twelve months, according to the manner of the women, (for so were the days of their purifications accomplished, to wit, six months with oil of myrrh, and six months with sweet odours, and with other things for the purifying of the women;)","words":[["H5291","Now when every maid's",0,21],["H8447","turn",22,26],["H5060","was come",27,35],["H0935","to go in",36,44],["H4428","to king",45,52],["H0325","Ahasuerus",53,62],["H7093","after",64,69],["H8147","that she had been twelve",70,94],["H6240","that she had been twelve",70,94],["H2320","months",95,101],["H1881","according to the manner",103,126],["H0802","of the women",127,139],["H3117","(for so were the days",141,162],["H4795","of their purifications",163,185],["H4390","accomplished",186,198],["H8337","to wit, six",200,211],["H2320","months",212,218],["H8081","with oil",219,227],["H4753","of myrrh",228,236],["H8337","and six",238,245],["H2320","months",246,252],["H1314","with sweet odours",253,270],["H8562","and with other things for the purifying",272,311],["H0802","of the women",312,324]]},"2:13":{"text":"Then thus came every maiden unto the king; whatsoever she desired was given her to go with her out of the house of the women unto the king's house.","words":[["H0935","Then thus came",0,14],["H5291","every maiden",15,27],["H4428","unto the king",28,41],["H0559","whatsoever she desired",43,65],["H5414","was given",66,75],["H0935","her to go",76,85],["H1004","with her out of the house",86,111],["H0802","of the women",112,124],["H4428","unto the king's",125,140],["H1004","house",141,146]]},"2:14":{"text":"In the evening she went, and on the morrow she returned into the second house of the women, to the custody of Shaashgaz, the king's chamberlain, which kept the concubines: she came in unto the king no more, except the king delighted in her, and that she were called by name.","words":[["H6153","In the evening",0,14],["H0935","she went",15,23],["H1242","and on the morrow",25,42],["H7725","she returned",43,55],["H8145","into the second",56,71],["H1004","house",72,77],["H0802","of the women",78,90],["H3027","to the custody",92,106],["H8190","of Shaashgaz",107,119],["H4428","the king's",121,131],["H5631","chamberlain",132,143],["H8104","which kept",145,155],["H6370","the concubines",156,170],["H0935","she came in",172,183],["H4428","unto the king",184,197],["H4428","no more, except the king",198,222],["H2654","delighted",223,232],["H7121","in her, and that she were called",233,265],["H8034","by name",266,273]]},"2:15":{"text":"Now when the turn of Esther, the daughter of Abihail the uncle of Mordecai, who had taken her for his daughter, was come to go in unto the king, she required nothing but what Hegai the king's chamberlain, the keeper of the women, appointed. And Esther obtained favour in the sight of all them that looked upon her.","words":[["H8447","Now when the turn",0,17],["H0635","of Esther",18,27],["H1323","the daughter",29,41],["H0032","of Abihail",42,52],["H1730","the uncle",53,62],["H4782","of Mordecai",63,74],["H3947","who had taken",76,89],["H1323","her for his daughter",90,110],["H5060","was come",112,120],["H0935","to go in",121,129],["H4428","unto the king",130,143],["H1245","she required",145,157],["H1697","nothing",158,165],["H1896","but what Hegai",166,180],["H4428","the king's",181,191],["H5631","chamberlain",192,203],["H8104","the keeper",205,215],["H0802","of the women",216,228],["H0559","appointed",230,239],["H0635","And Esther",241,251],["H5375","obtained",252,260],["H2580","favour",261,267],["H5869","in the sight",268,280],["H7200","of all them that looked",281,304]]},"2:16":{"text":"So Esther was taken unto king Ahasuerus into his house royal in the tenth month, which is the month Tebeth, in the seventh year of his reign.","words":[["H0635","So Esther",0,9],["H3947","was taken",10,19],["H4428","unto king",20,29],["H0325","Ahasuerus",30,39],["H1004","into his house",40,54],["H4438","royal",55,60],["H6224","in the tenth",61,73],["H2320","month",74,79],["H2320","which is the month",81,99],["H2887","Tebeth",100,106],["H7651","in the seventh",108,122],["H8141","year",123,127],["H4438","of his reign",128,140]]},"2:17":{"text":"And the king loved Esther above all the women, and she obtained grace and favour in his sight more than all the virgins; so that he set the royal crown upon her head, and made her queen instead of Vashti.","words":[["H4428","And the king",0,12],["H0157","loved",13,18],["H0635","Esther",19,25],["H0802","above all the women",26,45],["H5375","and she obtained",47,63],["H2580","grace",64,69],["H2617","and favour",70,80],["H6440","in his sight",81,93],["H1330","more than all the virgins",94,119],["H7760","so that he set",121,135],["H4438","the royal",136,145],["H3804","crown",146,151],["H7218","upon her head",152,165],["H4427","and made her queen",167,185],["H2060","instead of Vashti",186,203]]},"2:18":{"text":"Then the king made a great feast unto all his princes and his servants, even Esther's feast; and he made a release to the provinces, and gave gifts, according to the state of the king.","words":[["H4428","Then the king",0,13],["H6213","made",14,18],["H1419","a great",19,26],["H4960","feast",27,32],["H8269","unto all his princes",33,53],["H5650","and his servants",54,70],["H0635","even Esther's",72,85],["H4960","feast",86,91],["H6213","and he made",93,104],["H2010","a release",105,114],["H4082","to the provinces",115,131],["H5414","and gave",133,141],["H4864","gifts",142,147],["H3027","according to the state",149,171],["H4428","of the king",172,183]]},"2:19":{"text":"And when the virgins were gathered together the second time, then Mordecai sat in the king's gate.","words":[["H1330","And when the virgins",0,20],["H6908","were gathered together",21,43],["H8145","the second time",44,59],["H4782","then Mordecai",61,74],["H3427","sat",75,78],["H4428","in the king's",79,92],["H8179","gate",93,97]]},"2:20":{"text":"Esther had not yet shewed her kindred nor her people; as Mordecai had charged her: for Esther did the commandment of Mordecai, like as when she was brought up with him.","words":[["H0635","Esther",0,6],["H5046","had not yet shewed",7,25],["H4138","her kindred",26,37],["H5971","nor her people",38,52],["H4782","as Mordecai",54,65],["H6680","had charged",66,77],["H0635","her: for Esther",78,93],["H6213","did",94,97],["H3982","the commandment",98,113],["H4782","of Mordecai",114,125],["H0545","like as when she was brought up",127,158]]},"2:21":{"text":"In those days, while Mordecai sat in the king's gate, two of the king's chamberlains, Bigthan and Teresh, of those which kept the door, were wroth, and sought to lay hand on the king Ahasuerus.","words":[["H3117","In those days",0,13],["H4782","while Mordecai",15,29],["H3427","sat",30,33],["H4428","in the king's",34,47],["H8179","gate",48,52],["H8147","two",54,57],["H4428","of the king's",58,71],["H5631","chamberlains",72,84],["H0904","Bigthan",86,93],["H8657","and Teresh",94,104],["H8104","of those which kept",106,125],["H5592","the door",126,134],["H7107","were wroth",136,146],["H1245","and sought",148,158],["H7971","to lay",159,165],["H3027","hand",166,170],["H4428","on the king",171,182],["H0325","Ahasuerus",183,192]]},"2:22":{"text":"And the thing was known to Mordecai, who told it unto Esther the queen; and Esther certified the king thereof in Mordecai's name.","words":[["H1697","And the thing",0,13],["H3045","was known",14,23],["H4782","to Mordecai",24,35],["H5046","who told",37,45],["H0635","it unto Esther",46,60],["H4436","the queen",61,70],["H0635","and Esther",72,82],["H0559","certified",83,92],["H4428","the king",93,101],["H4782","thereof in Mordecai's",102,123],["H8034","name",124,128]]},"2:23":{"text":"And when inquisition was made of the matter, it was found out; therefore they were both hanged on a tree: and it was written in the book of the chronicles before the king.","words":[["H1245","And when inquisition",0,20],["H1697","was made of the matter",21,43],["H4672","it was found out",45,61],["H8147","therefore they were both",63,87],["H8518","hanged",88,94],["H6086","on a tree",95,104],["H3789","and it was written",106,124],["H5612","in the book",125,136],["H1697","of the chronicles",137,154],["H3117","of the chronicles",137,154],["H6440","before",155,161],["H4428","the king",162,170]]},"3:1":{"text":"After these things did king Ahasuerus promote Haman the son of Hammedatha the Agagite, and advanced him, and set his seat above all the princes that were with him.","words":[["H0310","After",0,5],["H1697","these things",6,18],["H4428","did king",19,27],["H0325","Ahasuerus",28,37],["H1431","promote",38,45],["H2001","Haman",46,51],["H1121","the son",52,59],["H4099","of Hammedatha",60,73],["H0091","the Agagite",74,85],["H5375","and advanced",87,99],["H7760","him, and set",100,112],["H3678","his seat",113,121],["H8269","above all the princes",122,143]]},"3:2":{"text":"And all the king's servants, that were in the king's gate, bowed, and reverenced Haman: for the king had so commanded concerning him. But Mordecai bowed not, nor did him reverence.","words":[["H4428","And all the king's",0,18],["H5650","servants",19,27],["H4428","that were in the king's",29,52],["H8179","gate",53,57],["H3766","bowed",59,64],["H7812","and reverenced",66,80],["H2001","Haman",81,86],["H4428","for the king",88,100],["H6680","had so commanded",101,117],["H4782","concerning him. But Mordecai",118,146],["H3766","bowed",147,152],["H7812","not, nor did him reverence",153,179]]},"3:3":{"text":"Then the king's servants, which were in the king's gate, said unto Mordecai, Why transgressest thou the king's commandment?","words":[["H4428","Then the king's",0,15],["H5650","servants",16,24],["H4428","which were in the king's",26,50],["H8179","gate",51,55],["H0559","said",57,61],["H4782","unto Mordecai",62,75],["H5674","Why transgressest",77,94],["H4428","thou the king's",95,110],["H4687","commandment",111,122]]},"3:4":{"text":"Now it came to pass, when they spake daily unto him, and he hearkened not unto them, that they told Haman, to see whether Mordecai's matters would stand: for he had told them that he was a Jew.","words":[["H0559","Now it came to pass, when they spake",0,36],["H3117","daily",37,42],["H3117","daily",37,42],["H8085","unto him, and he hearkened",43,69],["H5046","not unto them, that they told",70,99],["H2001","Haman",100,105],["H7200","to see",107,113],["H4782","whether Mordecai's",114,132],["H1697","matters",133,140],["H5975","would stand",141,152],["H5046","for he had told",154,169],["H3064","them that he was a Jew",170,192]]},"3:5":{"text":"And when Haman saw that Mordecai bowed not, nor did him reverence, then was Haman full of wrath.","words":[["H2001","And when Haman",0,14],["H7200","saw",15,18],["H4782","that Mordecai",19,32],["H3766","bowed",33,38],["H7812","not, nor did him reverence",39,65],["H2001","then was Haman",67,81],["H4390","full",82,86],["H2534","of wrath",87,95]]},"3:6":{"text":"And he thought scorn to lay hands on Mordecai alone; for they had shewed him the people of Mordecai: wherefore Haman sought to destroy all the Jews that were throughout the whole kingdom of Ahasuerus, even the people of Mordecai.","words":[["H5869","And he thought",0,14],["H0959","scorn",15,20],["H7971","to lay",21,27],["H3027","hands",28,33],["H4782","on Mordecai",34,45],["H5046","alone; for they had shewed",46,72],["H5971","him the people",73,87],["H4782","of Mordecai",88,99],["H2001","wherefore Haman",101,116],["H1245","sought",117,123],["H8045","to destroy",124,134],["H3064","all the Jews",135,147],["H4438","that were throughout the whole kingdom",148,186],["H0325","of Ahasuerus",187,199],["H5971","even the people",201,216],["H4782","of Mordecai",217,228]]},"3:7":{"text":"In the first month, that is, the month Nisan, in the twelfth year of king Ahasuerus, they cast Pur, that is, the lot, before Haman from day to day, and from month to month, to the twelfth month, that is, the month Adar.","words":[["H7223","In the first",0,12],["H2320","month",13,18],["H2320","that is, the month",20,38],["H5212","Nisan",39,44],["H8147","in the twelfth",46,60],["H6240","in the twelfth",46,60],["H8141","year",61,65],["H4428","of king",66,73],["H0325","Ahasuerus",74,83],["H5307","they cast",85,94],["H6332","Pur",95,98],["H1486","that is, the lot",100,116],["H6440","before",118,124],["H2001","Haman",125,130],["H3117","from day",131,139],["H3117","to day",140,146],["H2320","and from month",148,162],["H2320","to month",163,171],["H8147","to the twelfth",173,187],["H6240","to the twelfth",173,187],["H2320","month, that is, the month",188,213],["H0143","Adar",214,218]]},"3:8":{"text":"And Haman said unto king Ahasuerus, There is a certain people scattered abroad and dispersed among the people in all the provinces of thy kingdom; and their laws are diverse from all people; neither keep they the king's laws: therefore it is not for the king's profit to suffer them.","words":[["H2001","And Haman",0,9],["H0559","said",10,14],["H4428","unto king",15,24],["H0325","Ahasuerus",25,34],["H3426","There is",36,44],["H0259","a certain",45,54],["H5971","people",55,61],["H6340","scattered abroad",62,78],["H6504","and dispersed",79,92],["H5971","among the people",93,109],["H4082","in all the provinces",110,130],["H4438","of thy kingdom",131,145],["H1881","and their laws",147,161],["H8138","are diverse",162,173],["H5971","from all people",174,189],["H6213","neither keep",191,203],["H4428","they the king's",204,219],["H1881","laws",220,224],["H4428","therefore it is not for the king's",226,260],["H7737","profit",261,267],["H3240","to suffer",268,277]]},"3:9":{"text":"If it please the king, let it be written that they may be destroyed: and I will pay ten thousand talents of silver to the hands of those that have the charge of the business, to bring it into the king's treasuries.","words":[["H2895","If it please",0,12],["H4428","the king",13,21],["H3789","let it be written",23,40],["H0006","that they may be destroyed",41,67],["H8254","and I will pay",69,83],["H6235","ten",84,87],["H0505","thousand",88,96],["H3603","talents",97,104],["H3701","of silver",105,114],["H3027","to the hands",115,127],["H6213","of those that have the charge",128,157],["H4399","of the business",158,173],["H0935","to bring",175,183],["H4428","it into the king's",184,202],["H1595","treasuries",203,213]]},"3:10":{"text":"And the king took his ring from his hand, and gave it unto Haman the son of Hammedatha the Agagite, the Jews' enemy.","words":[["H4428","And the king",0,12],["H5493","took",13,17],["H2885","his ring",18,26],["H3027","from his hand",27,40],["H5414","and gave",42,50],["H2001","it unto Haman",51,64],["H1121","the son",65,72],["H4099","of Hammedatha",73,86],["H0091","the Agagite",87,98],["H3064","the Jews'",100,109],["H6887","enemy",110,115]]},"3:11":{"text":"And the king said unto Haman, The silver is given to thee, the people also, to do with them as it seemeth good to thee.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H2001","unto Haman",18,28],["H3701","The silver",30,40],["H5414","is given",41,49],["H5971","to thee, the people",50,69],["H6213","also, to do",70,81],["H5869","with them as it seemeth",82,105],["H2896","good",106,110]]},"3:12":{"text":"Then were the king's scribes called on the thirteenth day of the first month, and there was written according to all that Haman had commanded unto the king's lieutenants, and to the governors that were over every province, and to the rulers of every people of every province according to the writing thereof, and to every people after their language; in the name of king Ahasuerus was it written, and sealed with the king's ring.","words":[["H4428","Then were the king's",0,20],["H5608","scribes",21,28],["H7121","called",29,35],["H7969","on the thirteenth",36,53],["H6240","on the thirteenth",36,53],["H3117","day",54,57],["H7223","of the first",58,70],["H2320","month",71,76],["H3789","and there was written",78,99],["H2001","according to all that Haman",100,127],["H6680","had commanded",128,141],["H4428","unto the king's",142,157],["H0323","lieutenants",158,169],["H6346","and to the governors",171,191],["H4082","that were over every province",192,221],["H8269","and to the rulers",223,240],["H5971","of every people",241,256],["H4082","of every province",257,274],["H3791","according to the writing",275,299],["H5971","thereof, and to every people",300,328],["H3956","after their language",329,349],["H8034","in the name",351,362],["H4428","of king",363,370],["H0325","Ahasuerus",371,380],["H3789","was it written",381,395],["H2856","and sealed",397,407],["H4428","with the king's",408,423],["H2885","ring",424,428]]},"3:13":{"text":"And the letters were sent by posts into all the king's provinces, to destroy, to kill, and to cause to perish, all Jews, both young and old, little children and women, in one day, even upon the thirteenth day of the twelfth month, which is the month Adar, and to take the spoil of them for a prey.","words":[["H5612","And the letters",0,15],["H7971","were sent",16,25],["H3027","by",26,28],["H7323","posts",29,34],["H4428","into all the king's",35,54],["H4082","provinces",55,64],["H8045","to destroy",66,76],["H2026","to kill",78,85],["H0006","and to cause to perish",87,109],["H3064","all Jews",111,119],["H5288","both young",121,131],["H2205","and old",132,139],["H2945","little children",141,156],["H0802","and women",157,166],["H0259","in one",168,174],["H3117","day",175,178],["H7969","even upon the thirteenth",180,204],["H6240","even upon the thirteenth",180,204],["H8147","day of the twelfth",205,223],["H6240","day of the twelfth",205,223],["H2320","month",224,229],["H2320","which is the month",231,249],["H0143","Adar",250,254],["H7998","and to take the spoil",256,277],["H0962","of them for a prey",278,296]]},"3:14":{"text":"The copy of the writing for a commandment to be given in every province was published unto all people, that they should be ready against that day.","words":[["H6572","The copy",0,8],["H3791","of the writing",9,23],["H1881","for a commandment",24,41],["H5414","to be given",42,53],["H4082","in every province",54,71],["H1540","was published",72,85],["H5971","unto all people",86,101],["H6264","that they should be ready",103,128],["H3117","against that day",129,145]]},"3:15":{"text":"The posts went out, being hastened by the king's commandment, and the decree was given in Shushan the palace. And the king and Haman sat down to drink; but the city Shushan was perplexed.","words":[["H7323","The posts",0,9],["H3318","went out",10,18],["H1765","being hastened",20,34],["H4428","by the king's",35,48],["H1697","commandment",49,60],["H1881","and the decree",62,76],["H5414","was given",77,86],["H7800","in Shushan",87,97],["H1002","the palace",98,108],["H4428","And the king",110,122],["H2001","and Haman",123,132],["H3427","sat down",133,141],["H8354","to drink",142,150],["H5892","but the city",152,164],["H7800","Shushan",165,172],["H0943","was perplexed",173,186]]},"4:1":{"text":"When Mordecai perceived all that was done, Mordecai rent his clothes, and put on sackcloth with ashes, and went out into the midst of the city, and cried with a loud and a bitter cry;","words":[["H4782","When Mordecai",0,13],["H3045","perceived",14,23],["H6213","all that was done",24,41],["H4782","Mordecai",43,51],["H7167","rent",52,56],["H0899","his clothes",57,68],["H3847","and put on",70,80],["H8242","sackcloth",81,90],["H0665","with ashes",91,101],["H3318","and went out",103,115],["H8432","into the midst",116,130],["H5892","of the city",131,142],["H2199","and cried",144,153],["H1419","with a loud",154,165],["H4751","and a bitter",166,178],["H2201","cry",179,182]]},"4:2":{"text":"And came even before the king's gate: for none might enter into the king's gate clothed with sackcloth.","words":[["H0935","And came",0,8],["H6440","even before",9,20],["H4428","the king's",21,31],["H8179","gate",32,36],["H0935","for none might enter",38,58],["H4428","into the king's",59,74],["H8179","gate",75,79],["H3830","clothed",80,87],["H8242","with sackcloth",88,102]]},"4:3":{"text":"And in every province, whithersoever the king's commandment and his decree came, there was great mourning among the Jews, and fasting, and weeping, and wailing; and many lay in sackcloth and ashes.","words":[["H4082","And in every province",0,21],["H4725","whithersoever",23,36],["H4428","the king's",37,47],["H1697","commandment",48,59],["H1881","and his decree",60,74],["H5060","came",75,79],["H1419","there was great",81,96],["H0060","mourning",97,105],["H3064","among the Jews",106,120],["H6685","and fasting",122,133],["H1065","and weeping",135,146],["H4553","and wailing",148,159],["H7227","and many",161,169],["H3331","lay",170,173],["H8242","in sackcloth",174,186],["H0665","and ashes",187,196]]},"4:4":{"text":"So Esther's maids and her chamberlains came and told it her. Then was the queen exceedingly grieved; and she sent raiment to clothe Mordecai, and to take away his sackcloth from him: but he received it not.","words":[["H0635","So Esther's",0,11],["H5291","maids",12,17],["H5631","and her chamberlains",18,38],["H0935","came",39,43],["H5046","and told",44,52],["H4436","it her. Then was the queen",53,79],["H3966","exceedingly",80,91],["H2342","grieved",92,99],["H7971","and she sent",101,113],["H0899","raiment",114,121],["H3847","to clothe",122,131],["H4782","Mordecai",132,140],["H5493","and to take away",142,158],["H8242","his sackcloth",159,172],["H6901","from him: but he received",173,198]]},"4:5":{"text":"Then called Esther for Hatach, one of the king's chamberlains, whom he had appointed to attend upon her, and gave him a commandment to Mordecai, to know what it was, and why it was.","words":[["H7121","Then called",0,11],["H0635","Esther",12,18],["H2047","for Hatach",19,29],["H4428","one of the king's",31,48],["H5631","chamberlains",49,61],["H5975","whom he had appointed",63,84],["H6440","to attend",85,94],["H6680","upon her, and gave him a commandment",95,131],["H4782","to Mordecai",132,143],["H3045","to know",145,152]]},"4:6":{"text":"So Hatach went forth to Mordecai unto the street of the city, which was before the king's gate.","words":[["H2047","So Hatach",0,9],["H3318","went forth",10,20],["H4782","to Mordecai",21,32],["H7339","unto the street",33,48],["H5892","of the city",49,60],["H6440","which was before",62,78],["H4428","the king's",79,89],["H8179","gate",90,94]]},"4:7":{"text":"And Mordecai told him of all that had happened unto him, and of the sum of the money that Haman had promised to pay to the king's treasuries for the Jews, to destroy them.","words":[["H4782","And Mordecai",0,12],["H5046","told",13,17],["H7136","him of all that had happened",18,46],["H6575","unto him, and of the sum",47,71],["H3701","of the money",72,84],["H2001","that Haman",85,95],["H0559","had promised",96,108],["H8254","to pay",109,115],["H4428","to the king's",116,129],["H1595","treasuries",130,140],["H3064","for the Jews",141,153],["H0006","to destroy",155,165]]},"4:8":{"text":"Also he gave him the copy of the writing of the decree that was given at Shushan to destroy them, to shew it unto Esther, and to declare it unto her, and to charge her that she should go in unto the king, to make supplication unto him, and to make request before him for her people.","words":[["H5414","Also he gave",0,12],["H6572","him the copy",13,25],["H3791","of the writing",26,40],["H1881","of the decree",41,54],["H5414","that was given",55,69],["H7800","at Shushan",70,80],["H8045","to destroy",81,91],["H7200","them, to shew",92,105],["H0635","it unto Esther",106,120],["H5046","and to declare",122,136],["H6680","it unto her, and to charge",137,163],["H0935","her that she should go in",164,189],["H4428","unto the king",190,203],["H2603","to make supplication",205,225],["H1245","unto him, and to make request",226,255],["H6440","before",256,262],["H5971","him for her people",263,281]]},"4:9":{"text":"And Hatach came and told Esther the words of Mordecai.","words":[["H2047","And Hatach",0,10],["H0935","came",11,15],["H5046","and told",16,24],["H0635","Esther",25,31],["H1697","the words",32,41],["H4782","of Mordecai",42,53]]},"4:10":{"text":"Again Esther spake unto Hatach, and gave him commandment unto Mordecai;","words":[["H0635","Again Esther",0,12],["H0559","spake",13,18],["H2047","unto Hatach",19,30],["H6680","and gave him commandment",32,56],["H4782","unto Mordecai",57,70]]},"4:11":{"text":"All the king's servants, and the people of the king's provinces, do know, that whosoever, whether man or woman, shall come unto the king into the inner court, who is not called, there is one law of his to put him to death, except such to whom the king shall hold out the golden sceptre, that he may live: but I have not been called to come in unto the king these thirty days.","words":[["H4428","All the king's",0,14],["H5650","servants",15,23],["H5971","and the people",25,39],["H4428","of the king's",40,53],["H4082","provinces",54,63],["H3045","do know",65,72],["H0376","that whosoever, whether man",74,101],["H0802","or woman",102,110],["H0935","shall come",112,122],["H4428","unto the king",123,136],["H6442","into the inner",137,151],["H2691","court",152,157],["H7121","who is not called",159,176],["H0259","there is one",178,190],["H1881","law",191,194],["H4191","of his to put him to death",195,221],["H0905","except",223,229],["H4428","such to whom the king",230,251],["H3447","shall hold out",252,266],["H2091","the golden",267,277],["H8275","sceptre",278,285],["H2421","that he may live",287,303],["H7121","but I have not been called",305,331],["H0935","to come in",332,342],["H4428","unto the king",343,356],["H7970","these thirty",357,369],["H3117","days",370,374]]},"4:12":{"text":"And they told to Mordecai Esther's words.","words":[["H5046","And they told",0,13],["H4782","to Mordecai",14,25],["H0635","Esther's",26,34],["H1697","words",35,40]]},"4:13":{"text":"Then Mordecai commanded to answer Esther, Think not with thyself that thou shalt escape in the king's house, more than all the Jews.","words":[["H4782","Then Mordecai",0,13],["H0559","commanded",14,23],["H7725","to answer",24,33],["H0635","Esther",34,40],["H1819","Think",42,47],["H5315","not with thyself",48,64],["H4422","that thou shalt escape",65,87],["H4428","in the king's",88,101],["H1004","house",102,107],["H3064","more than all the Jews",109,131]]},"4:14":{"text":"For if thou altogether holdest thy peace at this time, then shall there enlargement and deliverance arise to the Jews from another place; but thou and thy father's house shall be destroyed: and who knoweth whether thou art come to the kingdom for such a time as this?","words":[["H2790","For if thou altogether",0,22],["H2790","holdest thy peace",23,40],["H6256","at this time",41,53],["H7305","then shall there enlargement",55,83],["H2020","and deliverance",84,99],["H5975","arise",100,105],["H3064","to the Jews",106,117],["H0312","from another",118,130],["H4725","place",131,136],["H0001","but thou and thy father's",138,163],["H1004","house",164,169],["H0006","shall be destroyed",170,188],["H3045","and who knoweth",190,205],["H5060","whether thou art come",206,227],["H4438","to the kingdom",228,242],["H6256","for such a time",243,258]]},"4:15":{"text":"Then Esther bade them return Mordecai this answer,","words":[["H0635","Then Esther",0,11],["H0559","bade",12,16],["H7725","them return",17,28],["H4782","Mordecai",29,37]]},"4:16":{"text":"Go, gather together all the Jews that are present in Shushan, and fast ye for me, and neither eat nor drink three days, night or day: I also and my maidens will fast likewise; and so will I go in unto the king, which is not according to the law: and if I perish, I perish.","words":[["H3212","Go",0,2],["H3664","gather together",4,19],["H3064","all the Jews",20,32],["H4672","that are present",33,49],["H7800","in Shushan",50,60],["H6684","and fast",62,70],["H0398","ye for me, and neither eat",71,97],["H8354","nor drink",98,107],["H7969","three",108,113],["H3117","days",114,118],["H3915","night",120,125],["H3117","or day",126,132],["H5291","I also and my maidens",134,155],["H6684","will fast",156,165],["H3651","likewise; and so",166,182],["H0935","will I go",183,192],["H4428","in unto the king",193,209],["H1881","which is not according to the law",211,244],["H0006","and if I perish",246,261],["H0006","I perish",263,271]]},"4:17":{"text":"So Mordecai went his way, and did according to all that Esther had commanded him.","words":[["H4782","So Mordecai",0,11],["H5674","went his way",12,24],["H6213","and did",26,33],["H0635","according to all that Esther",34,62],["H6680","had commanded",63,76]]},"5:1":{"text":"Now it came to pass on the third day, that Esther put on her royal apparel, and stood in the inner court of the king's house, over against the king's house: and the king sat upon his royal throne in the royal house, over against the gate of the house.","words":[["H7992","Now it came to pass on the third",0,32],["H3117","day",33,36],["H0635","that Esther",38,49],["H3847","put on",50,56],["H4438","her royal",57,66],["H5975","apparel, and stood",67,85],["H6442","in the inner",86,98],["H2691","court",99,104],["H4428","of the king's",105,118],["H1004","house",119,124],["H5227","over against",126,138],["H4428","the king's",139,149],["H1004","house",150,155],["H4428","and the king",157,169],["H3427","sat",170,173],["H4438","upon his royal",174,188],["H3678","throne",189,195],["H4438","in the royal",196,208],["H1004","house",209,214],["H5227","over against",216,228],["H6607","the gate",229,237],["H1004","of the house",238,250]]},"5:2":{"text":"And it was so, when the king saw Esther the queen standing in the court, that she obtained favour in his sight: and the king held out to Esther the golden sceptre that was in his hand. So Esther drew near, and touched the top of the sceptre.","words":[["H4428","And it was so, when the king",0,28],["H7200","saw",29,32],["H0635","Esther",33,39],["H4436","the queen",40,49],["H5975","standing",50,58],["H2691","in the court",59,71],["H5375","that she obtained",73,90],["H2580","favour",91,97],["H5869","in his sight",98,110],["H4428","and the king",112,124],["H3447","held out",125,133],["H0635","to Esther",134,143],["H2091","the golden",144,154],["H8275","sceptre",155,162],["H3027","that was in his hand",163,183],["H0635","So Esther",185,194],["H7126","drew near",195,204],["H5060","and touched",206,217],["H7218","the top",218,225],["H8275","of the sceptre",226,240]]},"5:3":{"text":"Then said the king unto her, What wilt thou, queen Esther? and what is thy request? it shall be even given thee to the half of the kingdom.","words":[["H0559","Then said",0,9],["H4428","the king",10,18],["H4436","unto her, What wilt thou, queen",19,50],["H0635","Esther",51,57],["H1246","and what is thy request",59,82],["H5414","it shall be even given",84,106],["H2677","thee to the half",107,123],["H4438","of the kingdom",124,138]]},"5:4":{"text":"And Esther answered, If it seem good unto the king, let the king and Haman come this day unto the banquet that I have prepared for him.","words":[["H0635","And Esther",0,10],["H0559","answered",11,19],["H2895","If it seem good",21,36],["H4428","unto the king",37,50],["H4428","let the king",52,64],["H2001","and Haman",65,74],["H0935","come",75,79],["H3117","this day",80,88],["H4960","unto the banquet",89,105],["H6213","that I have prepared",106,126]]},"5:5":{"text":"Then the king said, Cause Haman to make haste, that he may do as Esther hath said. So the king and Haman came to the banquet that Esther had prepared.","words":[["H4428","Then the king",0,13],["H0559","said",14,18],["H2001","Cause Haman",20,31],["H4116","to make haste",32,45],["H6213","that he may do",47,61],["H0635","as Esther",62,71],["H1697","hath said",72,81],["H4428","So the king",83,94],["H2001","and Haman",95,104],["H0935","came",105,109],["H4960","to the banquet",110,124],["H0635","that Esther",125,136],["H6213","had prepared",137,149]]},"5:6":{"text":"And the king said unto Esther at the banquet of wine, What is thy petition? and it shall be granted thee: and what is thy request? even to the half of the kingdom it shall be performed.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H0635","unto Esther",18,29],["H4960","at the banquet",30,44],["H3196","of wine",45,52],["H7596","What is thy petition",54,74],["H5414","and it shall be granted",76,99],["H1246","thee: and what is thy request",100,129],["H2677","even to the half",131,147],["H4438","of the kingdom",148,162],["H6213","it shall be performed",163,184]]},"5:7":{"text":"Then answered Esther, and said, My petition and my request is;","words":[["H6030","Then answered",0,13],["H0635","Esther",14,20],["H0559","and said",22,30],["H7596","My petition",32,43],["H1246","and my request",44,58]]},"5:8":{"text":"If I have found favour in the sight of the king, and if it please the king to grant my petition, and to perform my request, let the king and Haman come to the banquet that I shall prepare for them, and I will do to morrow as the king hath said.","words":[["H4672","If I have found",0,15],["H2580","favour",16,22],["H5869","in the sight",23,35],["H4428","of the king",36,47],["H2895","and if it please",49,65],["H4428","the king",66,74],["H5414","to grant",75,83],["H7596","my petition",84,95],["H6213","and to perform",97,111],["H1246","my request",112,122],["H4428","let the king",124,136],["H2001","and Haman",137,146],["H0935","come",147,151],["H4960","to the banquet",152,166],["H6213","that I shall prepare",167,187],["H6213","for them, and I will do",188,211],["H4279","to morrow",212,221],["H4428","as the king",222,233],["H1697","hath said",234,243]]},"5:9":{"text":"Then went Haman forth that day joyful and with a glad heart: but when Haman saw Mordecai in the king's gate, that he stood not up, nor moved for him, he was full of indignation against Mordecai.","words":[["H3318","Then went",0,9],["H2001","Haman",10,15],["H3318","forth",16,21],["H3117","that day",22,30],["H8056","joyful",31,37],["H2896","and with a glad",38,53],["H3820","heart",54,59],["H2001","but when Haman",61,75],["H7200","saw",76,79],["H4782","Mordecai",80,88],["H4428","in the king's",89,102],["H8179","gate",103,107],["H6965","that he stood not up",109,129],["H2111","nor moved",131,140],["H2001","for him, he",141,152],["H4390","was full",153,161],["H2534","of indignation",162,176],["H4782","against Mordecai",177,193]]},"5:10":{"text":"Nevertheless Haman refrained himself: and when he came home, he sent and called for his friends, and Zeresh his wife.","words":[["H2001","Nevertheless Haman",0,18],["H0662","refrained",19,28],["H0935","himself: and when he came",29,54],["H1004","home",55,59],["H7971","he sent",61,68],["H0935","and called",69,79],["H0157","for his friends",80,95],["H2238","and Zeresh",97,107],["H0802","his wife",108,116]]},"5:11":{"text":"And Haman told them of the glory of his riches, and the multitude of his children, and all the things wherein the king had promoted him, and how he had advanced him above the princes and servants of the king.","words":[["H2001","And Haman",0,9],["H5608","told",10,14],["H3519","them of the glory",15,32],["H6239","of his riches",33,46],["H7230","and the multitude",48,65],["H1121","of his children",66,81],["H4428","and all the things wherein the king",83,118],["H1431","had promoted",119,131],["H5375","him, and how he had advanced",132,160],["H8269","him above the princes",161,182],["H5650","and servants",183,195],["H4428","of the king",196,207]]},"5:12":{"text":"Haman said moreover, Yea, Esther the queen did let no man come in with the king unto the banquet that she had prepared but myself; and to morrow am I invited unto her also with the king.","words":[["H2001","Haman",0,5],["H0559","said",6,10],["H0635","moreover, Yea, Esther",11,32],["H4436","the queen",33,42],["H0935","did let no man come in",43,65],["H4428","with the king",66,79],["H4960","unto the banquet",80,96],["H6213","that she had prepared",97,118],["H4279","but myself; and to morrow",119,144],["H7121","am I invited",145,157],["H4428","unto her also with the king",158,185]]},"5:13":{"text":"Yet all this availeth me nothing, so long as I see Mordecai the Jew sitting at the king's gate.","words":[["H7737","Yet all this availeth",0,21],["H6256","me nothing, so long as",22,44],["H7200","I see",45,50],["H4782","Mordecai",51,59],["H3064","the Jew",60,67],["H3427","sitting",68,75],["H4428","at the king's",76,89],["H8179","gate",90,94]]},"5:14":{"text":"Then said Zeresh his wife and all his friends unto him, Let a gallows be made of fifty cubits high, and to morrow speak thou unto the king that Mordecai may be hanged thereon: then go thou in merrily with the king unto the banquet. And the thing pleased Haman; and he caused the gallows to be made.","words":[["H0559","Then said",0,9],["H2238","Zeresh",10,16],["H0802","his wife",17,25],["H0157","and all his friends",26,45],["H6086","unto him, Let a gallows",46,69],["H6213","be made",70,77],["H2572","of fifty",78,86],["H0520","cubits",87,93],["H1364","high",94,98],["H1242","and to morrow",100,113],["H0559","speak",114,119],["H4428","thou unto the king",120,138],["H4782","that Mordecai",139,152],["H8518","may be hanged",153,166],["H0935","thereon: then go",167,183],["H8056","thou in merrily",184,199],["H4428","with the king",200,213],["H4960","unto the banquet",214,230],["H1697","And the thing",232,245],["H3190","pleased",246,253],["H6440","pleased",246,253],["H2001","Haman",254,259],["H6213","and he caused",261,274],["H6086","the gallows",275,286],["H6213","to be made",287,297]]},"6:1":{"text":"On that night could not the king sleep, and he commanded to bring the book of records of the chronicles; and they were read before the king.","words":[["H3915","On that night",0,13],["H5074","could not",14,23],["H4428","the king",24,32],["H8142","sleep",33,38],["H0559","and he commanded",40,56],["H0935","to bring",57,65],["H5612","the book",66,74],["H2146","of records",75,85],["H1697","of the chronicles",86,103],["H3117","of the chronicles",86,103],["H7121","and they were read",105,123],["H6440","before",124,130],["H4428","the king",131,139]]},"6:2":{"text":"And it was found written, that Mordecai had told of Bigthana and Teresh, two of the king's chamberlains, the keepers of the door, who sought to lay hand on the king Ahasuerus.","words":[["H4672","And it was found",0,16],["H3789","written",17,24],["H4782","that Mordecai",26,39],["H5046","had told",40,48],["H0904","of Bigthana",49,60],["H8657","and Teresh",61,71],["H8147","two",73,76],["H4428","of the king's",77,90],["H5631","chamberlains",91,103],["H8104","the keepers",105,116],["H5592","of the door",117,128],["H1245","who sought",130,140],["H7971","to lay",141,147],["H3027","hand",148,152],["H4428","on the king",153,164],["H0325","Ahasuerus",165,174]]},"6:3":{"text":"And the king said, What honour and dignity hath been done to Mordecai for this? Then said the king's servants that ministered unto him, There is nothing done for him.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H3366","What honour",19,30],["H1420","and dignity",31,42],["H6213","hath been done",43,57],["H4782","to Mordecai",58,69],["H0559","for this? Then said",70,89],["H4428","the king's",90,100],["H5288","servants",101,109],["H8334","that ministered",110,125],["H1697","unto him, There is nothing",126,152],["H6213","done",153,157]]},"6:4":{"text":"And the king said, Who is in the court? Now Haman was come into the outward court of the king's house, to speak unto the king to hang Mordecai on the gallows that he had prepared for him.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H2691","Who is in the court",19,38],["H2001","Now Haman",40,49],["H0935","was come",50,58],["H2435","into the outward",59,75],["H2691","court",76,81],["H4428","of the king's",82,95],["H1004","house",96,101],["H0559","to speak",103,111],["H4428","unto the king",112,125],["H8518","to hang",126,133],["H4782","Mordecai",134,142],["H6086","on the gallows",143,157],["H3559","that he had prepared",158,178]]},"6:5":{"text":"And the king's servants said unto him, Behold, Haman standeth in the court. And the king said, Let him come in.","words":[["H4428","And the king's",0,14],["H5288","servants",15,23],["H0559","said",24,28],["H2001","unto him, Behold, Haman",29,52],["H5975","standeth",53,61],["H2691","in the court",62,74],["H4428","And the king",76,88],["H0559","said",89,93],["H0935","Let him come in",95,110]]},"6:6":{"text":"So Haman came in. And the king said unto him, What shall be done unto the man whom the king delighteth to honour? Now Haman thought in his heart, To whom would the king delight to do honour more than to myself?","words":[["H2001","So Haman",0,8],["H0935","came in",9,16],["H4428","And the king",18,30],["H0559","said",31,35],["H6213","unto him, What shall be done",36,64],["H0376","unto the man",65,77],["H4428","whom the king",78,91],["H2654","delighteth",92,102],["H3366","to honour",103,112],["H2001","Now Haman",114,123],["H0559","thought",124,131],["H3820","in his heart",132,144],["H4428","To whom would the king",146,168],["H2654","delight",169,176],["H6213","to do",177,182],["H3366","honour",183,189],["H3148","more",190,194]]},"6:7":{"text":"And Haman answered the king, For the man whom the king delighteth to honour,","words":[["H2001","And Haman",0,9],["H0559","answered",10,18],["H4428","the king",19,27],["H0376","For the man",29,40],["H4428","whom the king",41,54],["H2654","delighteth",55,65],["H3366","to honour",66,75]]},"6:8":{"text":"Let the royal apparel be brought which the king useth to wear, and the horse that the king rideth upon, and the crown royal which is set upon his head:","words":[["H4438","Let the royal",0,13],["H3830","apparel",14,21],["H0935","be brought",22,32],["H4428","which the king",33,47],["H3847","useth to wear",48,61],["H5483","and the horse",63,76],["H4428","that the king",77,90],["H7392","rideth",91,97],["H3804","upon, and the crown",98,117],["H4438","royal",118,123],["H5414","which is set",124,136],["H7218","upon his head",137,150]]},"6:9":{"text":"And let this apparel and horse be delivered to the hand of one of the king's most noble princes, that they may array the man withal whom the king delighteth to honour, and bring him on horseback through the street of the city, and proclaim before him, Thus shall it be done to the man whom the king delighteth to honour.","words":[["H3830","And let this apparel",0,20],["H5483","and horse",21,30],["H5414","be delivered",31,43],["H3027","to the hand",44,55],["H0376","of one",56,62],["H4428","of the king's",63,76],["H6579","most noble",77,87],["H8269","princes",88,95],["H3847","that they may array",97,116],["H0376","the man",117,124],["H4428","withal whom the king",125,145],["H2654","delighteth",146,156],["H3366","to honour",157,166],["H7392","and bring",168,177],["H5483","him on horseback",178,194],["H7339","through the street",195,213],["H5892","of the city",214,225],["H7121","and proclaim",227,239],["H6440","before",240,246],["H6213","him, Thus shall it be done",247,273],["H0376","to the man",274,284],["H4428","whom the king",285,298],["H2654","delighteth",299,309],["H3366","to honour",310,319]]},"6:10":{"text":"Then the king said to Haman, Make haste, and take the apparel and the horse, as thou hast said, and do even so to Mordecai the Jew, that sitteth at the king's gate: let nothing fail of all that thou hast spoken.","words":[["H4428","Then the king",0,13],["H0559","said",14,18],["H2001","to Haman",19,27],["H4116","Make haste",29,39],["H3947","and take",41,49],["H3830","the apparel",50,61],["H5483","and the horse",62,75],["H1696","as thou hast said",77,94],["H6213","and do",96,102],["H4782","even so to Mordecai",103,122],["H3064","the Jew",123,130],["H3427","that sitteth",132,144],["H4428","at the king's",145,158],["H8179","gate",159,163],["H1697","let nothing",165,176],["H5307","fail",177,181],["H1696","of all that thou hast spoken",182,210]]},"6:11":{"text":"Then took Haman the apparel and the horse, and arrayed Mordecai, and brought him on horseback through the street of the city, and proclaimed before him, Thus shall it be done unto the man whom the king delighteth to honour.","words":[["H3947","Then took",0,9],["H2001","Haman",10,15],["H3830","the apparel",16,27],["H5483","and the horse",28,41],["H3847","and arrayed",43,54],["H4782","Mordecai",55,63],["H7392","and brought him on horseback",65,93],["H7339","through the street",94,112],["H5892","of the city",113,124],["H7121","and proclaimed",126,140],["H6440","before",141,147],["H6213","him, Thus shall it be done",148,174],["H0376","unto the man",175,187],["H4428","whom the king",188,201],["H2654","delighteth",202,212],["H3366","to honour",213,222]]},"6:12":{"text":"And Mordecai came again to the king's gate. But Haman hasted to his house mourning, and having his head covered.","words":[["H4782","And Mordecai",0,12],["H7725","came again",13,23],["H4428","to the king's",24,37],["H8179","gate",38,42],["H2001","But Haman",44,53],["H1765","hasted",54,60],["H1004","to his house",61,73],["H0057","mourning",74,82],["H7218","and having his head",84,103],["H2645","covered",104,111]]},"6:13":{"text":"And Haman told Zeresh his wife and all his friends every thing that had befallen him. Then said his wise men and Zeresh his wife unto him, If Mordecai be of the seed of the Jews, before whom thou hast begun to fall, thou shalt not prevail against him, but shalt surely fall before him.","words":[["H2001","And Haman",0,9],["H5608","told",10,14],["H2238","Zeresh",15,21],["H0802","his wife",22,30],["H0157","and all his friends",31,50],["H7136","every thing that had befallen",51,80],["H0559","him. Then said",81,95],["H2450","his wise men",96,108],["H2238","and Zeresh",109,119],["H0802","his wife",120,128],["H4782","unto him, If Mordecai",129,150],["H2233","be of the seed",151,165],["H3064","of the Jews",166,177],["H6440","before",179,185],["H2490","whom thou hast begun",186,206],["H5307","to fall",207,214],["H3201","thou shalt not prevail",216,238],["H5307","against him, but shalt surely",239,268],["H5307","fall",269,273],["H6440","before",274,280]]},"6:14":{"text":"And while they were yet talking with him, came the king's chamberlains, and hasted to bring Haman unto the banquet that Esther had prepared.","words":[["H1696","And while they were yet talking",0,31],["H5060","with him, came",32,46],["H4428","the king's",47,57],["H5631","chamberlains",58,70],["H0926","and hasted",72,82],["H0935","to bring",83,91],["H2001","Haman",92,97],["H4960","unto the banquet",98,114],["H0635","that Esther",115,126],["H6213","had prepared",127,139]]},"7:1":{"text":"So the king and Haman came to banquet with Esther the queen.","words":[["H4428","So the king",0,11],["H2001","and Haman",12,21],["H0935","came",22,26],["H8354","to banquet",27,37],["H0635","with Esther",38,49],["H4436","the queen",50,59]]},"7:2":{"text":"And the king said again unto Esther on the second day at the banquet of wine, What is thy petition, queen Esther? and it shall be granted thee: and what is thy request? and it shall be performed, even to the half of the kingdom.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H0635","again unto Esther",18,35],["H8145","on the second",36,49],["H3117","day",50,53],["H4960","at the banquet",54,68],["H3196","of wine",69,76],["H7596","What is thy petition",78,98],["H4436","queen",100,105],["H0635","Esther",106,112],["H5414","and it shall be granted",114,137],["H1246","thee: and what is thy request",138,167],["H6213","and it shall be performed",169,194],["H2677","even to the half",196,212],["H4438","of the kingdom",213,227]]},"7:3":{"text":"Then Esther the queen answered and said, If I have found favour in thy sight, O king, and if it please the king, let my life be given me at my petition, and my people at my request:","words":[["H0635","Then Esther",0,11],["H4436","the queen",12,21],["H6030","answered",22,30],["H0559","and said",31,39],["H4672","If I have found",41,56],["H2580","favour",57,63],["H5869","in thy sight",64,76],["H4428","O king",78,84],["H2895","and if it please",86,102],["H4428","the king",103,111],["H5315","let my life",113,124],["H5414","be given",125,133],["H7596","me at my petition",134,151],["H5971","and my people",153,166],["H1246","at my request",167,180]]},"7:4":{"text":"For we are sold, I and my people, to be destroyed, to be slain, and to perish. But if we had been sold for bondmen and bondwomen, I had held my tongue, although the enemy could not countervail the king's damage.","words":[["H4376","For we are sold",0,15],["H5971","I and my people",17,32],["H8045","to be destroyed",34,49],["H2026","to be slain",51,62],["H0006","and to perish",64,77],["H0432","But if",79,85],["H4376","we had been sold",86,102],["H5650","for bondmen",103,114],["H8198","and bondwomen",115,128],["H2790","I had held my tongue",130,150],["H6862","although the enemy",152,170],["H7737","could not countervail",171,192],["H4428","the king's",193,203],["H5143","damage",204,210]]},"7:5":{"text":"Then the king Ahasuerus answered and said unto Esther the queen, Who is he, and where is he, that durst presume in his heart to do so?","words":[["H4428","Then the king",0,13],["H0325","Ahasuerus",14,23],["H0559","answered",24,32],["H0559","and said",33,41],["H0635","unto Esther",42,53],["H4436","the queen",54,63],["H4390","Who is he, and where is he, that durst presume",65,111],["H3820","in his heart",112,124],["H6213","to do",125,130]]},"7:6":{"text":"And Esther said, The adversary and enemy is this wicked Haman. Then Haman was afraid before the king and the queen.","words":[["H0635","And Esther",0,10],["H0559","said",11,15],["H0376","The adversary",17,30],["H6862","The adversary",17,30],["H0341","and enemy",31,40],["H7451","is this wicked",41,55],["H2001","Haman",56,61],["H2001","Then Haman",63,73],["H1204","was afraid",74,84],["H6440","before",85,91],["H4428","the king",92,100],["H4436","and the queen",101,114]]},"7:7":{"text":"And the king arising from the banquet of wine in his wrath went into the palace garden: and Haman stood up to make request for his life to Esther the queen; for he saw that there was evil determined against him by the king.","words":[["H4428","And the king",0,12],["H6965","arising",13,20],["H4960","from the banquet",21,37],["H3196","of wine",38,45],["H2534","in his wrath",46,58],["H1055","went into the palace",59,79],["H1594","garden",80,86],["H2001","and Haman",88,97],["H5975","stood up",98,106],["H1245","to make request",107,122],["H5315","for his life",123,135],["H0635","to Esther",136,145],["H4436","the queen",146,155],["H7200","for he saw",157,167],["H7451","that there was evil",168,187],["H3615","determined",188,198],["H4428","against him by the king",199,222]]},"7:8":{"text":"Then the king returned out of the palace garden into the place of the banquet of wine; and Haman was fallen upon the bed whereon Esther was. Then said the king, Will he force the queen also before me in the house? As the word went out of the king's mouth, they covered Haman's face.","words":[["H4428","Then the king",0,13],["H7725","returned",14,22],["H1055","out of the palace",23,40],["H1594","garden",41,47],["H1004","into the place",48,62],["H4960","of the banquet",63,77],["H3196","of wine",78,85],["H2001","and Haman",87,96],["H5307","was fallen",97,107],["H4296","upon the bed",108,120],["H0635","whereon Esther",121,135],["H0559","was. Then said",136,150],["H4428","the king",151,159],["H3533","Will he force",161,174],["H4436","the queen",175,184],["H1004","also before me in the house",185,212],["H1697","As the word",214,225],["H3318","went out",226,234],["H4428","of the king's",235,248],["H6310","mouth",249,254],["H2645","they covered",256,268],["H2001","Haman's",269,276],["H6440","face",277,281]]},"7:9":{"text":"And Harbonah, one of the chamberlains, said before the king, Behold also, the gallows fifty cubits high, which Haman had made for Mordecai, who had spoken good for the king, standeth in the house of Haman. Then the king said, Hang him thereon.","words":[["H2726","And Harbonah",0,12],["H0259","one",14,17],["H5631","of the chamberlains",18,37],["H0559","said",39,43],["H6440","before",44,50],["H4428","the king",51,59],["H6086","Behold also, the gallows",61,85],["H2572","fifty",86,91],["H0520","cubits",92,98],["H1364","high",99,103],["H2001","which Haman",105,116],["H6213","had made",117,125],["H4782","for Mordecai",126,138],["H1696","who had spoken",140,154],["H2896","good",155,159],["H4428","for the king",160,172],["H5975","standeth",174,182],["H1004","in the house",183,195],["H2001","of Haman",196,204],["H4428","Then the king",206,219],["H0559","said",220,224],["H8518","Hang",226,230]]},"7:10":{"text":"So they hanged Haman on the gallows that he had prepared for Mordecai. Then was the king's wrath pacified.","words":[["H8518","So they hanged",0,14],["H2001","Haman",15,20],["H6086","on the gallows",21,35],["H3559","that he had prepared",36,56],["H4782","for Mordecai",57,69],["H4428","Then was the king's",71,90],["H2534","wrath",91,96],["H7918","pacified",97,105]]},"8:1":{"text":"On that day did the king Ahasuerus give the house of Haman the Jews' enemy unto Esther the queen. And Mordecai came before the king; for Esther had told what he was unto her.","words":[["H3117","On that day",0,11],["H4428","did the king",12,24],["H0325","Ahasuerus",25,34],["H5414","give",35,39],["H1004","the house",40,49],["H2001","of Haman",50,58],["H3064","the Jews'",59,68],["H6887","enemy",69,74],["H0635","unto Esther",75,86],["H4436","the queen",87,96],["H4782","And Mordecai",98,110],["H0935","came",111,115],["H6440","before",116,122],["H4428","the king",123,131],["H0635","for Esther",133,143],["H5046","had told",144,152]]},"8:2":{"text":"And the king took off his ring, which he had taken from Haman, and gave it unto Mordecai. And Esther set Mordecai over the house of Haman.","words":[["H4428","And the king",0,12],["H5493","took off",13,21],["H2885","his ring",22,30],["H5674","which he had taken",32,50],["H2001","from Haman",51,61],["H5414","and gave",63,71],["H4782","it unto Mordecai",72,88],["H0635","And Esther",90,100],["H7760","set",101,104],["H4782","Mordecai",105,113],["H1004","over the house",114,128],["H2001","of Haman",129,137]]},"8:3":{"text":"And Esther spake yet again before the king, and fell down at his feet, and besought him with tears to put away the mischief of Haman the Agagite, and his device that he had devised against the Jews.","words":[["H0635","And Esther",0,10],["H1696","spake",11,16],["H3254","yet again",17,26],["H6440","before",27,33],["H4428","the king",34,42],["H5307","and fell down",44,57],["H6440","at",58,60],["H7272","his feet",61,69],["H2603","and besought",71,83],["H1058","him with tears",84,98],["H5674","to put away",99,110],["H7451","the mischief",111,123],["H2001","of Haman",124,132],["H0091","the Agagite",133,144],["H4284","and his device",146,160],["H2803","that he had devised",161,180],["H3064","against the Jews",181,197]]},"8:4":{"text":"Then the king held out the golden sceptre toward Esther. So Esther arose, and stood before the king,","words":[["H4428","Then the king",0,13],["H3447","held out",14,22],["H2091","the golden",23,33],["H8275","sceptre",34,41],["H0635","toward Esther",42,55],["H0635","So Esther",57,66],["H6965","arose",67,72],["H5975","and stood",74,83],["H6440","before",84,90],["H4428","the king",91,99]]},"8:5":{"text":"And said, If it please the king, and if I have found favour in his sight, and the thing seem right before the king, and I be pleasing in his eyes, let it be written to reverse the letters devised by Haman the son of Hammedatha the Agagite, which he wrote to destroy the Jews which are in all the king's provinces:","words":[["H0559","And said",0,8],["H2896","If it please",10,22],["H4428","the king",23,31],["H4672","and if I have found",33,52],["H2580","favour",53,59],["H6440","in his sight",60,72],["H1697","and the thing",74,87],["H3787","seem right",88,98],["H6440","before",99,105],["H4428","the king",106,114],["H2896","and I be pleasing",116,133],["H5869","in his eyes",134,145],["H3789","let it be written",147,164],["H7725","to reverse",165,175],["H5612","the letters",176,187],["H4284","devised",188,195],["H2001","by Haman",196,204],["H1121","the son",205,212],["H4099","of Hammedatha",213,226],["H0091","the Agagite",227,238],["H3789","which he wrote",240,254],["H0006","to destroy",255,265],["H3064","the Jews",266,274],["H4428","which are in all the king's",275,302],["H4082","provinces",303,312]]},"8:6":{"text":"For how can I endure to see the evil that shall come unto my people? or how can I endure to see the destruction of my kindred?","words":[["H0349","For how",0,7],["H3201","can I endure",8,20],["H7200","to see",21,27],["H7451","the evil",28,36],["H4672","that shall come",37,52],["H5971","unto my people",53,67],["H0349","or how",69,75],["H3201","can I endure",76,88],["H7200","to see",89,95],["H0013","the destruction",96,111],["H4138","of my kindred",112,125]]},"8:7":{"text":"Then the king Ahasuerus said unto Esther the queen and to Mordecai the Jew, Behold, I have given Esther the house of Haman, and him they have hanged upon the gallows, because he laid his hand upon the Jews.","words":[["H4428","Then the king",0,13],["H0325","Ahasuerus",14,23],["H0559","said",24,28],["H0635","unto Esther",29,40],["H4436","the queen",41,50],["H4782","and to Mordecai",51,66],["H3064","the Jew",67,74],["H5414","Behold, I have given",76,96],["H0635","Esther",97,103],["H1004","the house",104,113],["H2001","of Haman",114,122],["H8518","and him they have hanged",124,148],["H6086","upon the gallows",149,165],["H7971","because he laid",167,182],["H3027","his hand",183,191],["H3064","upon the Jews",192,205]]},"8:8":{"text":"Write ye also for the Jews, as it liketh you, in the king's name, and seal it with the king's ring: for the writing which is written in the king's name, and sealed with the king's ring, may no man reverse.","words":[["H3789","Write",0,5],["H3064","ye also for the Jews",6,26],["H2896","as it liketh",28,40],["H5869","you",41,44],["H4428","in the king's",46,59],["H8034","name",60,64],["H2856","and seal",66,74],["H4428","it with the king's",75,93],["H2885","ring",94,98],["H3791","for the writing",100,115],["H3789","which is written",116,132],["H4428","in the king's",133,146],["H8034","name",147,151],["H2856","and sealed",153,163],["H4428","with the king's",164,179],["H2885","ring",180,184],["H7725","may no man reverse",186,204]]},"8:9":{"text":"Then were the king's scribes called at that time in the third month, that is, the month Sivan, on the three and twentieth day thereof; and it was written according to all that Mordecai commanded unto the Jews, and to the lieutenants, and the deputies and rulers of the provinces which are from India unto Ethiopia, an hundred twenty and seven provinces, unto every province according to the writing thereof, and unto every people after their language, and to the Jews according to their writing, and according to their language.","words":[["H4428","Then were the king's",0,20],["H5608","scribes",21,28],["H7121","called",29,35],["H6256","at that time",36,48],["H7992","in the third",49,61],["H2320","month",62,67],["H2320","that is, the month",69,87],["H5510","Sivan",88,93],["H7969","on the three",95,107],["H6242","and twentieth",108,121],["H3789","day thereof; and it was written",122,153],["H4782","according to all that Mordecai",154,184],["H6680","commanded",185,194],["H3064","unto the Jews",195,208],["H0323","and to the lieutenants",210,232],["H6346","and the deputies",234,250],["H8269","and rulers",251,261],["H4082","of the provinces",262,278],["H1912","which are from India",279,299],["H3568","unto Ethiopia",300,313],["H3967","an hundred",315,325],["H6242","twenty",326,332],["H7651","and seven",333,342],["H4082","provinces",343,352],["H4082","unto every province",354,373],["H3791","according to the writing",374,398],["H5971","thereof, and unto every people",399,429],["H3956","after their language",430,450],["H3064","and to the Jews",452,467],["H3791","according to their writing",468,494],["H3956","and according to their language",496,527]]},"8:10":{"text":"And he wrote in the king Ahasuerus' name, and sealed it with the king's ring, and sent letters by posts on horseback, and riders on mules, camels, and young dromedaries:","words":[["H3789","And he wrote",0,12],["H4428","in the king",13,24],["H0325","Ahasuerus'",25,35],["H8034","name",36,40],["H2856","and sealed",42,52],["H4428","it with the king's",53,71],["H2885","ring",72,76],["H7971","and sent",78,86],["H5612","letters",87,94],["H3027","by",95,97],["H7323","posts",98,103],["H5483","on horseback",104,116],["H7392","and riders",118,128],["H7409","on mules",129,137],["H0327","camels",139,145],["H1121","and young",147,156],["H7424","dromedaries",157,168]]},"8:11":{"text":"Wherein the king granted the Jews which were in every city to gather themselves together, and to stand for their life, to destroy, to slay, and to cause to perish, all the power of the people and province that would assault them, both little ones and women, and to take the spoil of them for a prey,","words":[["H4428","Wherein the king",0,16],["H5414","granted",17,24],["H3064","the Jews",25,33],["H5892","which were in every city",34,58],["H6950","to gather themselves together",59,88],["H5975","and to stand",90,102],["H5315","for their life",103,117],["H8045","to destroy",119,129],["H2026","to slay",131,138],["H0006","and to cause to perish",140,162],["H2428","all the power",164,177],["H5971","of the people",178,191],["H4082","and province",192,204],["H6696","that would assault",205,223],["H2945","them, both little ones",224,246],["H0802","and women",247,256],["H7998","and to take the spoil",258,279],["H0962","of them for a prey",280,298]]},"8:12":{"text":"Upon one day in all the provinces of king Ahasuerus, namely, upon the thirteenth day of the twelfth month, which is the month Adar.","words":[["H0259","Upon one",0,8],["H3117","day",9,12],["H4082","in all the provinces",13,33],["H4428","of king",34,41],["H0325","Ahasuerus",42,51],["H7969","namely, upon the thirteenth",53,80],["H6240","namely, upon the thirteenth",53,80],["H8147","day of the twelfth",81,99],["H6240","day of the twelfth",81,99],["H2320","month",100,105],["H2320","which is the month",107,125],["H0143","Adar",126,130]]},"8:13":{"text":"The copy of the writing for a commandment to be given in every province was published unto all people, and that the Jews should be ready against that day to avenge themselves on their enemies.","words":[["H6572","The copy",0,8],["H3791","of the writing",9,23],["H1881","for a commandment",24,41],["H5414","to be given",42,53],["H4082","in every province",54,71],["H1540","was published",72,85],["H5971","unto all people",86,101],["H3064","and that the Jews",103,120],["H6264","should be ready",121,136],["H6259","should be ready",121,136],["H3117","against that day",137,153],["H5358","to avenge",154,163],["H0341","themselves on their enemies",164,191]]},"8:14":{"text":"So the posts that rode upon mules and camels went out, being hastened and pressed on by the king's commandment. And the decree was given at Shushan the palace.","words":[["H7323","So the posts",0,12],["H7392","that rode",13,22],["H7409","upon mules",23,33],["H0327","and camels",34,44],["H3318","went out",45,53],["H0926","being hastened",55,69],["H1765","and pressed on",70,84],["H4428","by the king's",85,98],["H1697","commandment",99,110],["H1881","And the decree",112,126],["H5414","was given",127,136],["H7800","at Shushan",137,147],["H1002","the palace",148,158]]},"8:15":{"text":"And Mordecai went out from the presence of the king in royal apparel of blue and white, and with a great crown of gold, and with a garment of fine linen and purple: and the city of Shushan rejoiced and was glad.","words":[["H4782","And Mordecai",0,12],["H3318","went out",13,21],["H6440","from the presence",22,39],["H4428","of the king",40,51],["H4438","in royal",52,60],["H3830","apparel",61,68],["H8504","of blue",69,76],["H2353","and white",77,86],["H1419","and with a great",88,104],["H5850","crown",105,110],["H2091","of gold",111,118],["H8509","and with a garment",120,138],["H0948","of fine linen",139,152],["H0713","and purple",153,163],["H5892","and the city",165,177],["H7800","of Shushan",178,188],["H6670","rejoiced",189,197],["H8056","and was glad",198,210]]},"8:16":{"text":"The Jews had light, and gladness, and joy, and honour.","words":[["H3064","The Jews",0,8],["H0219","had light",9,18],["H8057","and gladness",20,32],["H8342","and joy",34,41],["H3366","and honour",43,53]]},"8:17":{"text":"And in every province, and in every city, whithersoever the king's commandment and his decree came, the Jews had joy and gladness, a feast and a good day. And many of the people of the land became Jews; for the fear of the Jews fell upon them.","words":[["H4082","And in every province",0,21],["H5892","and in every city",23,40],["H4725","whithersoever",42,55],["H4428","the king's",56,66],["H1697","commandment",67,78],["H1881","and his decree",79,93],["H5060","came",94,98],["H3064","the Jews",100,108],["H8057","had joy",109,116],["H8342","and gladness",117,129],["H4960","a feast",131,138],["H2896","and a good",139,149],["H3117","day",150,153],["H7227","And many",155,163],["H5971","of the people",164,177],["H0776","of the land",178,189],["H3054","became Jews",190,201],["H6343","for the fear",203,215],["H3064","of the Jews",216,227],["H5307","fell",228,232]]},"9:1":{"text":"Now in the twelfth month, that is, the month Adar, on the thirteenth day of the same, when the king's commandment and his decree drew near to be put in execution, in the day that the enemies of the Jews hoped to have power over them, (though it was turned to the contrary, that the Jews had rule over them that hated them;)","words":[["H8147","Now in the twelfth",0,18],["H6240","Now in the twelfth",0,18],["H2320","month",19,24],["H2320","that is, the month",26,44],["H0143","Adar",45,49],["H7969","on the thirteenth",51,68],["H6240","on the thirteenth",51,68],["H3117","day",69,72],["H4428","of the same, when the king's",73,101],["H1697","commandment",102,113],["H1881","and his decree",114,128],["H5060","drew near",129,138],["H6213","to be put in execution",139,161],["H3117","in the day",163,173],["H0341","that the enemies",174,190],["H3064","of the Jews",191,202],["H7663","hoped",203,208],["H7980","to have power",209,222],["H2015","over them, (though it was turned",223,255],["H3064","to the contrary, that the Jews",256,286],["H7980","had rule",287,295],["H8130","over them that hated",296,316]]},"9:2":{"text":"The Jews gathered themselves together in their cities throughout all the provinces of the king Ahasuerus, to lay hand on such as sought their hurt: and no man could withstand them; for the fear of them fell upon all people.","words":[["H3064","The Jews",0,8],["H6950","gathered themselves together",9,37],["H5892","in their cities",38,53],["H4082","throughout all the provinces",54,82],["H4428","of the king",83,94],["H0325","Ahasuerus",95,104],["H7971","to lay",106,112],["H3027","hand",113,117],["H1245","on such as sought",118,135],["H7451","their hurt",136,146],["H0376","and no man",148,158],["H5975","could withstand",159,174],["H6440","them",175,179],["H6343","for the fear",181,193],["H5307","of them fell",194,206],["H5971","upon all people",207,222]]},"9:3":{"text":"And all the rulers of the provinces, and the lieutenants, and the deputies, and officers of the king, helped the Jews; because the fear of Mordecai fell upon them.","words":[["H8269","And all the rulers",0,18],["H4082","of the provinces",19,35],["H0323","and the lieutenants",37,56],["H6346","and the deputies",58,74],["H6213","and officers",76,88],["H4399","and officers",76,88],["H4428","of the king",89,100],["H5375","helped",102,108],["H3064","the Jews",109,117],["H6343","because the fear",119,135],["H4782","of Mordecai",136,147],["H5307","fell",148,152]]},"9:4":{"text":"For Mordecai was great in the king's house, and his fame went out throughout all the provinces: for this man Mordecai waxed greater and greater.","words":[["H4782","For Mordecai",0,12],["H1419","was great",13,22],["H4428","in the king's",23,36],["H1004","house",37,42],["H8089","and his fame",44,56],["H1980","went out",57,65],["H4082","throughout all the provinces",66,94],["H0376","for this man",96,108],["H4782","Mordecai",109,117],["H1980","waxed",118,123],["H1419","greater and greater",124,143]]},"9:5":{"text":"Thus the Jews smote all their enemies with the stroke of the sword, and slaughter, and destruction, and did what they would unto those that hated them.","words":[["H3064","Thus the Jews",0,13],["H5221","smote",14,19],["H0341","all their enemies",20,37],["H4347","with the stroke",38,53],["H2719","of the sword",54,66],["H2027","and slaughter",68,81],["H0012","and destruction",83,98],["H6213","and did",100,107],["H7522","what they would",108,123],["H8130","unto those that hated",124,145]]},"9:6":{"text":"And in Shushan the palace the Jews slew and destroyed five hundred men.","words":[["H7800","And in Shushan",0,14],["H1002","the palace",15,25],["H3064","the Jews",26,34],["H2026","slew",35,39],["H0006","and destroyed",40,53],["H2568","five",54,58],["H3967","hundred",59,66],["H0376","men",67,70]]},"9:7":{"text":"And Parshandatha, and Dalphon, and Aspatha,","words":[["H6577","And Parshandatha",0,16],["H1813","and Dalphon",18,29],["H0630","and Aspatha",31,42]]},"9:8":{"text":"And Poratha, and Adalia, and Aridatha,","words":[["H6334","And Poratha",0,11],["H0118","and Adalia",13,23],["H0743","and Aridatha",25,37]]},"9:9":{"text":"And Parmashta, and Arisai, and Aridai, and Vajezatha,","words":[["H6534","And Parmashta",0,13],["H0747","and Arisai",15,25],["H0742","and Aridai",27,37],["H2055","and Vajezatha",39,52]]},"9:10":{"text":"The ten sons of Haman the son of Hammedatha, the enemy of the Jews, slew they; but on the spoil laid they not their hand.","words":[["H6235","The ten",0,7],["H1121","sons",8,12],["H2001","of Haman",13,21],["H1121","the son",22,29],["H4099","of Hammedatha",30,43],["H6887","the enemy",45,54],["H3064","of the Jews",55,66],["H2026","slew",68,72],["H0961","they; but on the spoil",73,95],["H7971","laid",96,100],["H3027","they not their hand",101,120]]},"9:11":{"text":"On that day the number of those that were slain in Shushan the palace was brought before the king.","words":[["H3117","On that day",0,11],["H4557","the number",12,22],["H2026","of those that were slain",23,47],["H7800","in Shushan",48,58],["H1002","the palace",59,69],["H0935","was brought",70,81],["H6440","before",82,88],["H4428","the king",89,97]]},"9:12":{"text":"And the king said unto Esther the queen, The Jews have slain and destroyed five hundred men in Shushan the palace, and the ten sons of Haman; what have they done in the rest of the king's provinces? now what is thy petition? and it shall be granted thee: or what is thy request further? and it shall be done.","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H0635","unto Esther",18,29],["H4436","the queen",30,39],["H3064","The Jews",41,49],["H2026","have slain",50,60],["H0006","and destroyed",61,74],["H2568","five",75,79],["H3967","hundred",80,87],["H0376","men",88,91],["H7800","in Shushan",92,102],["H1002","the palace",103,113],["H6235","and the ten",115,126],["H1121","sons",127,131],["H2001","of Haman",132,140],["H6213","what have they done",142,161],["H7605","in the rest",162,173],["H4428","of the king's",174,187],["H4082","provinces",188,197],["H7596","now what is thy petition",199,223],["H5414","and it shall be granted",225,248],["H1246","thee: or what is thy request",249,277],["H5750","further",278,285],["H6213","and it shall be done",287,307]]},"9:13":{"text":"Then said Esther, If it please the king, let it be granted to the Jews which are in Shushan to do to morrow also according unto this day's decree, and let Haman's ten sons be hanged upon the gallows.","words":[["H0559","Then said",0,9],["H0635","Esther",10,16],["H2896","If it please",18,30],["H4428","the king",31,39],["H5414","let it be granted",41,58],["H3064","to the Jews",59,70],["H7800","which are in Shushan",71,91],["H6213","to do",92,97],["H4279","to morrow",98,107],["H3117","also according unto this day's",108,138],["H1881","decree",139,145],["H2001","and let Haman's",147,162],["H6235","ten",163,166],["H1121","sons",167,171],["H8518","be hanged",172,181],["H6086","upon the gallows",182,198]]},"9:14":{"text":"And the king commanded it so to be done: and the decree was given at Shushan; and they hanged Haman's ten sons.","words":[["H4428","And the king",0,12],["H0559","commanded",13,22],["H6213","it so to be done",23,39],["H1881","and the decree",41,55],["H5414","was given",56,65],["H7800","at Shushan",66,76],["H8518","and they hanged",78,93],["H2001","Haman's",94,101],["H6235","ten",102,105],["H1121","sons",106,110]]},"9:15":{"text":"For the Jews that were in Shushan gathered themselves together on the fourteenth day also of the month Adar, and slew three hundred men at Shushan; but on the prey they laid not their hand.","words":[["H3064","For the Jews",0,12],["H7800","that were in Shushan",13,33],["H6950","gathered themselves together",34,62],["H0702","on the fourteenth",63,80],["H6240","on the fourteenth",63,80],["H3117","day",81,84],["H2320","also of the month",85,102],["H0143","Adar",103,107],["H2026","and slew",109,117],["H7969","three",118,123],["H3967","hundred",124,131],["H0376","men",132,135],["H7800","at Shushan",136,146],["H0961","but on the prey",148,163],["H7971","they laid",164,173],["H3027","not their hand",174,188]]},"9:16":{"text":"But the other Jews that were in the king's provinces gathered themselves together, and stood for their lives, and had rest from their enemies, and slew of their foes seventy and five thousand, but they laid not their hands on the prey,","words":[["H7605","But the other",0,13],["H3064","Jews",14,18],["H4428","that were in the king's",19,42],["H4082","provinces",43,52],["H6950","gathered themselves together",53,81],["H5975","and stood",83,92],["H5315","for their lives",93,108],["H5118","and had rest",110,122],["H0341","from their enemies",123,141],["H2026","and slew",143,151],["H8130","of their foes",152,165],["H7657","seventy",166,173],["H2568","and five",174,182],["H0505","thousand",183,191],["H7971","but they laid",193,206],["H3027","not their hands",207,222],["H0961","on the prey",223,234]]},"9:17":{"text":"On the thirteenth day of the month Adar; and on the fourteenth day of the same rested they, and made it a day of feasting and gladness.","words":[["H7969","On the thirteenth",0,17],["H6240","On the thirteenth",0,17],["H3117","day",18,21],["H2320","of the month",22,34],["H0143","Adar",35,39],["H0702","and on the fourteenth",41,62],["H6240","and on the fourteenth",41,62],["H5118","day of the same rested",63,85],["H6213","they, and made",86,100],["H3117","it a day",101,109],["H4960","of feasting",110,121],["H8057","and gladness",122,134]]},"9:18":{"text":"But the Jews that were at Shushan assembled together on the thirteenth day thereof, and on the fourteenth thereof; and on the fifteenth day of the same they rested, and made it a day of feasting and gladness.","words":[["H3064","But the Jews",0,12],["H7800","that were at Shushan",13,33],["H6950","assembled together",34,52],["H7969","on the thirteenth",53,70],["H6240","on the thirteenth",53,70],["H0702","day thereof, and on the fourteenth",71,105],["H6240","day thereof, and on the fourteenth",71,105],["H2568","thereof; and on the fifteenth",106,135],["H6240","thereof; and on the fifteenth",106,135],["H5118","day of the same they rested",136,163],["H6213","and made",165,173],["H3117","it a day",174,182],["H4960","of feasting",183,194],["H8057","and gladness",195,207]]},"9:19":{"text":"Therefore the Jews of the villages, that dwelt in the unwalled towns, made the fourteenth day of the month Adar a day of gladness and feasting, and a good day, and of sending portions one to another.","words":[["H3064","Therefore the Jews",0,18],["H6521","of the villages",19,34],["H3427","that dwelt",36,46],["H6519","in the unwalled",47,62],["H5892","towns",63,68],["H6213","made",70,74],["H0702","the fourteenth",75,89],["H6240","the fourteenth",75,89],["H3117","day",90,93],["H2320","of the month",94,106],["H0143","Adar",107,111],["H8057","a day of gladness",112,129],["H4960","and feasting",130,142],["H2896","and a good",144,154],["H3117","day",155,158],["H4916","and of sending",160,174],["H4490","portions",175,183],["H0376","one",184,187],["H7453","to another",188,198]]},"9:20":{"text":"And Mordecai wrote these things, and sent letters unto all the Jews that were in all the provinces of the king Ahasuerus, both nigh and far,","words":[["H4782","And Mordecai",0,12],["H3789","wrote",13,18],["H1697","these things",19,31],["H7971","and sent",33,41],["H5612","letters",42,49],["H3064","unto all the Jews",50,67],["H4082","that were in all the provinces",68,98],["H4428","of the king",99,110],["H0325","Ahasuerus",111,120],["H7138","both nigh",122,131],["H7350","and far",132,139]]},"9:21":{"text":"To stablish this among them, that they should keep the fourteenth day of the month Adar, and the fifteenth day of the same, yearly,","words":[["H6965","To stablish",0,11],["H6213","this among them, that they should keep",12,50],["H0702","the fourteenth",51,65],["H6240","the fourteenth",51,65],["H3117","day",66,69],["H2320","of the month",70,82],["H0143","Adar",83,87],["H2568","and the fifteenth",89,106],["H6240","and the fifteenth",89,106],["H3117","day",107,110],["H8141","of the same, yearly",111,130],["H8141","of the same, yearly",111,130]]},"9:22":{"text":"As the days wherein the Jews rested from their enemies, and the month which was turned unto them from sorrow to joy, and from mourning into a good day: that they should make them days of feasting and joy, and of sending portions one to another, and gifts to the poor.","words":[["H3117","As the days",0,11],["H3064","wherein the Jews",12,28],["H5117","rested",29,35],["H0341","from their enemies",36,54],["H2320","and the month",56,69],["H2015","which was turned",70,86],["H3015","unto them from sorrow",87,108],["H8057","to joy",109,115],["H0060","and from mourning",117,134],["H2896","into a good",135,146],["H3117","day",147,150],["H6213","that they should make",152,173],["H3117","them days",174,183],["H4960","of feasting",184,195],["H8057","and joy",196,203],["H4916","and of sending",205,219],["H4490","portions",220,228],["H0376","one",229,232],["H7453","to another",233,243],["H4979","and gifts",245,254],["H0034","to the poor",255,266]]},"9:23":{"text":"And the Jews undertook to do as they had begun, and as Mordecai had written unto them;","words":[["H3064","And the Jews",0,12],["H6901","undertook",13,22],["H6213","to do",23,28],["H2490","as they had begun",29,46],["H4782","and as Mordecai",48,63],["H3789","had written",64,75]]},"9:24":{"text":"Because Haman the son of Hammedatha, the Agagite, the enemy of all the Jews, had devised against the Jews to destroy them, and had cast Pur, that is, the lot, to consume them, and to destroy them;","words":[["H2001","Because Haman",0,13],["H1121","the son",14,21],["H4099","of Hammedatha",22,35],["H0091","the Agagite",37,48],["H6887","the enemy",50,59],["H3064","of all the Jews",60,75],["H2803","had devised",77,88],["H3064","against the Jews",89,105],["H0006","to destroy",106,116],["H5307","them, and had cast",117,135],["H6332","Pur",136,139],["H1486","that is, the lot",141,157],["H2000","to consume",159,169],["H0006","them, and to destroy",170,190]]},"9:25":{"text":"But when Esther came before the king, he commanded by letters that his wicked device, which he devised against the Jews, should return upon his own head, and that he and his sons should be hanged on the gallows.","words":[["H0935","But when Esther came",0,20],["H6440","before",21,27],["H4428","the king",28,36],["H0559","he commanded",38,50],["H5612","by letters",51,61],["H7451","that his wicked",62,77],["H4284","device",78,84],["H2803","which he devised",86,102],["H3064","against the Jews",103,119],["H7725","should return",121,134],["H7218","upon his own head",135,152],["H1121","and that he and his sons",154,178],["H8518","should be hanged",179,195],["H6086","on the gallows",196,210]]},"9:26":{"text":"Wherefore they called these days Purim after the name of Pur. Therefore for all the words of this letter, and of that which they had seen concerning this matter, and which had come unto them,","words":[["H7121","Wherefore they called",0,21],["H3117","these days",22,32],["H6332","Purim",33,38],["H8034","after the name",39,53],["H6332","of Pur",54,60],["H1697","Therefore for all the words",62,89],["H0107","of this letter",90,104],["H7200","and of that which they had seen",106,137],["H3602","concerning this matter",138,160],["H5060","and which had come",162,180]]},"9:27":{"text":"The Jews ordained, and took upon them, and upon their seed, and upon all such as joined themselves unto them, so as it should not fail, that they would keep these two days according to their writing, and according to their appointed time every year;","words":[["H3064","The Jews",0,8],["H6965","ordained",9,17],["H6901","and took",19,27],["H2233","upon them, and upon their seed",28,58],["H3867","and upon all such as joined",60,87],["H5674","themselves unto them, so as it should not fail",88,134],["H6213","that they would keep",136,156],["H8147","these two",157,166],["H3117","days",167,171],["H3791","according to their writing",172,198],["H2165","and according to their appointed time",200,237],["H8141","every year",238,248],["H8141","every year",238,248]]},"9:28":{"text":"And that these days should be remembered and kept throughout every generation, every family, every province, and every city; and that these days of Purim should not fail from among the Jews, nor the memorial of them perish from their seed.","words":[["H3117","And that these days",0,19],["H2142","should be remembered",20,40],["H6213","and kept",41,49],["H1755","throughout",50,60],["H1755","every generation",61,77],["H4940","every family",79,91],["H4082","every province",93,107],["H5892","and every city",109,123],["H3117","and that these days",125,144],["H6332","of Purim",145,153],["H5674","should not fail",154,169],["H8432","from among",170,180],["H3064","the Jews",181,189],["H2143","nor the memorial",191,207],["H5486","of them perish",208,222],["H2233","from their seed",223,238]]},"9:29":{"text":"Then Esther the queen, the daughter of Abihail, and Mordecai the Jew, wrote with all authority, to confirm this second letter of Purim.","words":[["H0635","Then Esther",0,11],["H4436","the queen",12,21],["H1323","the daughter",23,35],["H0032","of Abihail",36,46],["H4782","and Mordecai",48,60],["H3064","the Jew",61,68],["H3789","wrote",70,75],["H8633","with all authority",76,94],["H6965","to confirm",96,106],["H8145","this second",107,118],["H0107","letter",119,125],["H6332","of Purim",126,134]]},"9:30":{"text":"And he sent the letters unto all the Jews, to the hundred twenty and seven provinces of the kingdom of Ahasuerus, with words of peace and truth,","words":[["H7971","And he sent",0,11],["H5612","the letters",12,23],["H3064","unto all the Jews",24,41],["H3967","to the hundred",43,57],["H6242","twenty",58,64],["H7651","and seven",65,74],["H4082","provinces",75,84],["H4438","of the kingdom",85,99],["H0325","of Ahasuerus",100,112],["H1697","with words",114,124],["H7965","of peace",125,133],["H0571","and truth",134,143]]},"9:31":{"text":"To confirm these days of Purim in their times appointed, according as Mordecai the Jew and Esther the queen had enjoined them, and as they had decreed for themselves and for their seed, the matters of the fastings and their cry.","words":[["H6965","To confirm",0,10],["H3117","these days",11,21],["H6332","of Purim",22,30],["H2165","in their times",31,45],["H4782","appointed, according as Mordecai",46,78],["H3064","the Jew",79,86],["H0635","and Esther",87,97],["H4436","the queen",98,107],["H6965","had enjoined",108,120],["H6965","them, and as they had decreed",121,150],["H5315","for themselves",151,165],["H2233","and for their seed",166,184],["H1697","the matters",186,197],["H6685","of the fastings",198,213],["H2201","and their cry",214,227]]},"9:32":{"text":"And the decree of Esther confirmed these matters of Purim; and it was written in the book.","words":[["H3982","And the decree",0,14],["H0635","of Esther",15,24],["H6965","confirmed",25,34],["H1697","these matters",35,48],["H6332","of Purim",49,57],["H3789","and it was written",59,77],["H5612","in the book",78,89]]},"10:1":{"text":"And the king Ahasuerus laid a tribute upon the land, and upon the isles of the sea.","words":[["H4428","And the king",0,12],["H0325","Ahasuerus",13,22],["H7760","laid",23,27],["H4522","a tribute",28,37],["H0776","upon the land",38,51],["H0339","and upon the isles",53,71],["H3220","of the sea",72,82]]},"10:2":{"text":"And all the acts of his power and of his might, and the declaration of the greatness of Mordecai, whereunto the king advanced him, are they not written in the book of the chronicles of the kings of Media and Persia?","words":[["H4639","And all the acts",0,16],["H8633","of his power",17,29],["H1369","and of his might",30,46],["H6575","and the declaration",48,67],["H1420","of the greatness",68,84],["H4782","of Mordecai",85,96],["H4428","whereunto the king",98,116],["H1431","advanced",117,125],["H3789","him, are they not written",126,151],["H5612","in the book",152,163],["H1697","of the chronicles",164,181],["H3117","of the chronicles",164,181],["H4428","of the kings",182,194],["H4074","of Media",195,203],["H6539","and Persia",204,214]]},"10:3":{"text":"For Mordecai the Jew was next unto king Ahasuerus, and great among the Jews, and accepted of the multitude of his brethren, seeking the wealth of his people, and speaking peace to all his seed.","words":[["H4782","For Mordecai",0,12],["H3064","the Jew",13,20],["H4932","was next",21,29],["H4428","unto king",30,39],["H0325","Ahasuerus",40,49],["H1419","and great",51,60],["H3064","among the Jews",61,75],["H7521","and accepted",77,89],["H7230","of the multitude",90,106],["H0251","of his brethren",107,122],["H1875","seeking",124,131],["H2896","the wealth",132,142],["H5971","of his people",143,156],["H1696","and speaking",158,170],["H7965","peace",171,176],["H2233","to all his seed",177,192]]}}};
